INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b86aacb2-8ff4-46f5-bf9a-effb9595e512', 'Διοικητικό πακέτων ακούσει συγγραφής παραγωγικής. Χρησιμοποίησέ χαμηλός βασανίζουν διάσημα ρωτάει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c08a8a93-f62b-4493-b25d-9c8820681584', 'Άπειρα ταξινομεί ατόμου μπορούσες εργαζόμενοι στο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f2e437d8-dd38-4207-8754-a17db2e6549a', 'Θα κανείς στο συνεχώς πετούν. Και δυστυχώς αποφάσισε των περιβάλλοντος άρα. Πιο εκτός μάλλον πρόσληψη σε λέει.', '123', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('483bf1df-1c22-4404-aacb-7d08a8ab4de4', 'Ανακλύψεις διάβασε προκύπτουν εκτός δυστυχώς.', '63', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a98a5503-4eb8-4e4c-9fe7-980a9f99172d', 'Έξι πόρτες ότι προγραμματιστής γραμμή άρα. Δε πόρτες ερωτήσεις δεδομένων χαμηλός. Αναγκάζονται πάντως κόψεις της γραφικά εργαλείων συνηθίζουν.', '120', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ef841dc4-dba5-49db-bdca-f3747d438224', 'Τύπους δημιουργείς άρα απαραίτητο εφαμοργής. Χρόνου πλέον γειτονιάς εργάστηκε. Τα πολύ που δουλεύει μα συγχωνευτεί έχω. Ποια εξαρτάται τι από φίλος εικόνες πρώτο.', '144', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d0f66cc2-43e7-43bb-826f-5c74478f302d', 'Κανόνα μα δημιουργήσεις δούλευε άρα μην. Παίξουν βασανίζουν διάβασε πάντως. Διασφαλίζεται και δύο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4e220e0c-7854-40fa-a04c-ff962b4ef769', 'Υψηλότερη είχαμε με σημεία απαράδεκτη αλγόριθμου. Πετάξαμε ως θέμα αρέσει μάλλον έτοιμος. Οι όχι τον καλύτερο ανταγωνιστής.', '81', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0a846f6c-593f-4e90-b6da-4fd8eae79539', 'Γραμμής ώρα ωραίο περίπου δίνοντας αγοράζοντας. Ατόμου δημιουργήσεις γεύματος σε τα στις.', '15', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6a6b5a82-365e-461e-8932-d04b5effbb02', 'Εικόνες διαχειριστής μαγικά ποια πάρα ακούσει δημιουργείς. Γέλασαν γραφικά επεξεργασία σπίτι. Πεδία εταιρείες διακόψουμε τους. Προϊόντα απαραίτητο κι αποδείξεις διολισθήσεις.', '57', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b0045e24-35e9-4dbe-94d8-4984554ed951', 'Τη εδώ όσο. Εδώ ποια αναγκάζονται το πάντα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a2ad7398-6335-4273-9ec5-1354a01c903f', 'Συνεχώς εφαρμογή χρησιμοποίησέ επιχείριση κειμένων κόψεις. Χρησιμοποίησέ τη πετούν περισσότερες έτσι σαν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1278edb1-046b-417c-8f18-f9e86f6ba3a9', 'Ερωτήσεις ακούσει ακούσει άλγεβρα στα δε ημέρα. Διοικητικό διορθώσεις έγραψες. Διαδίκτυο εσωτερικών κοιτάζοντας ρουτίνα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8a00eb69-895a-43a9-ba0a-4841050ce85e', 'Επί δημιουργήσεις κανένας έρθει επεξεργασία. Απαραίτητο αρπάζεις όσο βιαστικά μάλλον εργάστηκε κάτι ποια.', '107', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cbe6d484-0c7d-4382-b99f-4d93ab236c46', 'Στη άρα μην διορθώσεις εργάστηκε. Του αναφορά δημιουργήσεις πακέτων φίλος ορίστε. Αρέσει κρατήσουν κι ανακλύψεις δεν χρόνου. Έστελνε ανώδυνη σημαντικός συνέχεια.', '91', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ac646203-7aed-41e1-85f7-608deb03522c', 'Γνωρίζουμε παραγωγικής έτσι δουλεύει. Οι γιαυτό μου πετούν τρόποι. Επιστρέφουν ανά εκθέσεις συγγραφής χρόνου.', '47', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('984ed9a6-b1b2-486c-8826-98ec4fa369b9', 'Τα μηχανής επιδιόρθωση εφαρμογής συνάδελφος. Χειρότερα γραφικά ροή προσοχή φράση κλπ ανώδυνη καταλάθος. Δημιουργια και εφαμοργής εταιρείες.', '35', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ffa79e65-3020-4ed3-a721-59be3012beef', 'Ακούσει εργοστασίου δεν ο στήλες το υόρκη επιδιόρθωση. Δείξει απίστευτα εκτελέσεις εκτός τις στις προσεκτικά εργάστηκε.', '145', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('66d124cb-03ce-4a42-a8b9-555d50fc3cb9', 'Τρέξει ανά πιο ως κώδικα γέλασαν. Δημιουργείς ώρα γιαυτό δεν χαρακτηριστικών κανόνα για. Χαμηλός εργάστηκε εγώ χρησιμοποίησέ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('14ddaa18-751d-4b71-b16e-588a3869b2de', 'Καταλάθος έτοιμος παράδειγμα ποσοστό. Έξι εργαλείων του αλγόριθμου χρησιμοποιώντας συνηθίζουν των εργασίας. Νιρβάνα τα ένα τέλειοι διακοπή.', '52', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('07bd46e5-bbc4-4904-ac83-22246ea60f20', 'Στη κοιτάζοντας ίδιο. Κοιτάζοντας έτσι δείξει πρώτο χώρου ανά πάντα. Σωστά επιδιορθώσεις στο βιαστικά μέχρι πιο διαπιστώνεις. Κρατάει έτοιμος έξι στέλνοντάς ευκολότερο χαρακτηριστικό ανώδυνη δύο.', '63', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c664d5ec-c1a8-4607-84aa-472b735040ce', 'Προκαλείς για θέμα πάντα λέει βγήκε. Πάντως αποκλειστικούς απομόνωση μεταγλωτιστής. Πετάξαμε από χώρου χαρτιού νόμιζες εργασίας.', '39', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('06d93c62-c2f1-4189-93a4-b67351c6ae18', 'Των παράγοντες γεγονός κανόνα αποφάσισε για. Εκτός ο εδώ συγχρόνως τα δημιουργήσεις πλέον κανείς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('296b7b5d-74ff-4409-899c-ccb903c07274', 'Παραπάνω ιδιαίτερα επιχείριση έστελνε ως αρχεία πόρτες. Ειδικά παράγοντες νέων διάσημα πιο για. Επιδιόρθωση μα ήδη μα άτομο χρονοδιαγράμματος.', '20', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1c6adffa-053c-4f0a-8b75-a43ba0b9a7e9', 'Ώρα επί μέχρι γνωστή αναφέρονται χρόνου οι. Τα πες προσπαθούν έστειλε της βιαστικά.', '6', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('64f8039b-cc40-470c-a543-d22867373b60', 'Δημιουργήσεις σωστά αφήσεις οι έχω ακούσει. Αντιλήφθηκαν χαρτιού περιεχόμενα τα διορθώσει προϊόντα. Πάρα δημιουργείς περίπου λιγότερο ένας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bd9dde6c-448b-492e-9a33-cd3a89b7851c', 'Έτσι ευκολότερο συνηθίζουν διολισθήσεις απαραίτητο προσεκτικά συνηθίζουν μάλλον. Αλγόριθμου πηγαίου δημιουργείς τον και τη σίγουρος έτσι. Των σχεδιαστής σαν όσο έστειλε.', '47', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6cfb6910-dc3a-41e5-bffb-90ab04f5baef', 'Ποια εκτελείται μετράει τελειώσει χρησιμοποιούνταν ευκολότερο. Ορίστε μαγικά εργασίας μπουν από επιστρέφουν σχεδιαστής. Τρόπο γειτονιάς το δημιουργείς.', '118', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('447302ce-0641-4ade-82f2-3bdb8d59aa3d', 'Έχω υψηλότερη τον δε. Παραδώσεις δύο οι σε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('813fcfdb-464f-4eef-801b-56ed898e6860', 'Δεδομένων εντολές σε πεδία. Πιο σίγουρος εκτελείται μια αλγόριθμου πως νέων. Πρόσληψη αυτήν πάρεις παίρνουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a339f7a2-5517-4253-991b-ba8c3d917874', 'Ποια ως ως έτσι. Απομόνωση πόρτες προσθέσει γνωστή. Μια με όσο παραπάνω νέων διακοπής.', '111', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('36ec3b47-87c1-4439-b261-a51afd6675a8', 'Φακέλους εκτός ρουτίνα πήρε διάβασε έτοιμος. Μη κανείς βασανίζουν θα κοιτάζοντας.', '66', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('11de254f-3f38-49ce-a972-5be05572835e', 'Έτσι νέο περισσότερη χρησιμοποίησέ. Πως αναφέρονται παραγωγικής για περισσότερη προσεκτικά ανεπιθύμητη. Περίπου στέλνοντάς ανώδυνη δύο ανά.', '108', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a3bc7ae8-494d-4839-963a-3877c3d99431', 'Δημιουργείς διευθυντές φράση συνέχεια. Ωραίο τρέξει θα έστελνε. Για εκτός τρόποι εκτός όσο στέλνοντάς κόψεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aef78e5b-3efc-4258-b611-76b9d0293416', 'Υόρκη μέγιστη όταν δείξει έστειλε έξι. Ρουτίνα δημιουργια πάντα μας απίστευτα χαμηλός φακέλους. Μη όταν εξακολουθεί κειμένων και.', '13', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('01064ddd-e2f7-4209-865a-e8ca25a25580', 'Διακόψουμε παραδώσεις πάρεις παράδειγμα εταιρείες δοκιμάσεις. Έξι των αν περιεχόμενα απομόνωση. Προγραμματιστής επεξεργασία χρονοδιαγράμματος.', '43', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5a64a94b-4dbc-458c-9dac-09058ce3d84f', 'Έτοιμος δύο πρώτο τα. Επί δεν τεκμηριώνει κώδικάς. Παίρνουν γέλασαν τρέξει χρειάζονται διοικητικό.', '58', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f9717257-f276-40fc-8f96-04509831866c', 'Δοκιμάσεις έχω δεν νέα ότι κανόνα προσεκτικά. Εκθέσεις ξέχασε κι αθόρυβες εδώ. Που πακέτων κλπ λοιπόν κάνεις.', '140', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5e40d768-f65f-4a76-9752-0c7e1a8b7c87', 'Ήδη δεν διοικητικό σας πάντα επιχείριση. Στραβά αρπάζεις χειρότερα τύπους πετάξαμε τύπους. Χρόνου τον οι δεν πάντα.', '7', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('783741f4-425b-480e-8974-47a10f5c5eb7', 'Χειρότερα πάντως αυτός κι σε έτσι έρθει. Σαν δεν μου μέγιστη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('210d9967-9911-46ee-909d-237d38fc9311', 'Κάτι μα ήδη δουλεύει έχω. Μερικούς φακέλους συνηθίζουν. Δε ανώδυνη όταν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fb128247-6b0f-4cdb-91cd-5649f17d5be9', 'Αφήσεις μέγιστη μην πρώτης άλγεβρα ανταγωνιστής. Ώρα όταν αν άρθρων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('337ada81-d8e9-4842-b7a0-d4bc9e092a46', 'Εργαζόμενων χρειάζονται γεγονός διάβασε δύο τρόποι. Μέσης διάβασε επί γνωστή όταν δοκιμάσεις εκτός. Για φαινόμενο τι ποια διορθώσεις κάνε.', '116', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('908b4b29-aea8-45f2-8153-da65f945369d', 'Δωροδοκηθούν εδώ τη στα νιρβάνα εξαρτάται δυστυχώς πάντως. Των αναγκάζονται κάτι εκθέσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8cf22881-9434-4b78-90bc-91076053dfa1', 'Ρωτήσει δημιουργείς εικόνες απαραίτητο πεδία αν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a3bb6b0d-704b-4320-9fa7-6fee39c2b9f5', 'Κώδικα προϊόντα βουτήξουν ρωτήσει καταλάθος ανά τι. Εκτός προσθέσει ποια και συνέχεια.', '54', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a9832c9b-8843-4549-b038-06aa1d266787', 'Νόμιζες στη απόλαυσε επεξεργασία πιο θέμα. Έτοιμος υόρκη άρα νέων σε συνηθίζουν πακέτων. Τρόποι δωροδοκηθούν τα τέλειοι ναι δυστυχής εφαμοργής.', '47', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a93399f1-ffa7-4471-821d-999617da56b2', 'Και επενδυτής γιαυτό εφαρμογή σαν. Λαμβάνουν σημαντικό κανείς ας μη τεκμηριώνει. Κάτι χώρου λες από.', '56', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d2cec8ba-b758-44e3-a5e1-2b5d2154cfee', 'Τέλειοι διαφήμιση συνάδελφος χρησιμοποίησέ περιμένουν πλέον τον μπουν. Προκαλείς αποδείξεις διευθυντές δε δύο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a78e4861-a091-487a-9ebe-7edae45b302b', 'Νιρβάνα έξι εξοργιστικά μου κύκλο. Πάρα ίδιο δε. Δεδομένων τις οι τον εργάστηκε ο.', '142', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0deadbc1-c77e-4e46-9492-4064705ff7cc', 'Τους διαχειριστής θα πετούν εξαρτάται πλέον για. Εδώ απίστευτα ένα έτσι φακέλους δουλεύει. Πετούν ποσοστό γραμμή.', '150', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dc19208e-d696-4f2f-bfa2-03237dfa10b4', 'Προσλάμβανες έστελνε πάρεις μη λίγο παίρνουν προσλάμβανες. Πηγαίου σας από εκθέσεις όταν αν. Απόλαυσε συγκεντρωμένοι πάρεις συνεχώς ας μέρος.', '41', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('29cfc48d-503e-4289-9456-b9ce668ebfe7', 'Ερωτήσεις φαινόμενο αποφάσισε προσλάμβανες ρουτίνα επιχείριση μου βγήκε. Χαρτιού συγχρόνως μεταγλωτιστής.', '110', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bafaf0a4-0044-4059-bf4d-0073d87022b4', 'Της μετρήσεις δοκιμάσεις μια τι αν διορθώσει βασανίζουν. Έλεγχος ανά εκτελέσεις απομόνωση.', '77', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8c3adb34-3476-4b42-9ffd-c6465be626c4', 'Παραδώσεις διάβασε συνηθίζουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f7a768c6-41bc-443f-981d-02bfd20cfe85', 'Προγραμματιστής λαμβάνουν με τύπου σε δουλεύει έξι. Εκδόσεις επιχείριση αν κλπ διαδίκτυο τοπικές.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('19ac5d8e-c6f7-4c6b-894a-000304541582', 'Διασφαλίζεται επί υψηλότερη ζητήσεις για τεσσαρών. Γραμμής δεδομένων μα ας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('084034f8-5492-45d5-8dbe-aaca1f28b866', 'Μέχρι υόρκη διάσημα ναι ρωτήσει. Σαν εδώ διορθώσει πολύ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('46eb21bc-b355-4709-b6c2-151665bb7bb3', 'Βαθμό πάντα πετάνε εκτελέσεις μια. Πλέον πρώτο απαρατήρητο έχω. Έτσι εργαζόμενων αναφέρονται τεσσαρών των περίπου.', '98', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ee942222-b32a-465a-bb71-ce2d64fbf7bb', 'Ότι ανταγωνιστής γραμμές άλγεβρα έξι εκτός. Άτομο ωραίο μας ήδη βασανίζουν προγραμματιστές πάντως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cf2d0c92-74bc-42ff-a6fc-3264df195c0b', 'Σας δύο στο λιγότερο περιβάλλοντος τους ας. Έγραψες κανείς μια μαγικά φίλος τύπου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9af31c1b-7ec5-4bb2-a23f-260808bae289', 'Ειδικά συγχωνευτεί κάνε ποσοστό εξαρτάται τον. Του γράψει κάνε διακοπή την εκτός. Πολύ μην ποια στις διάσημα ανακλύψεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('24c2ef83-a277-4d4d-8225-9a049f326ffd', 'Εκτελέσεις προσθέσει διευθυντές μα αν. Υόρκη σε εκθέσεις δεν λες όταν δοκιμάσεις. Διορθώσεις πως προγραμματιστές δεν εκθέσεις αυτός δυστυχώς παραδώσεις.', '147', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('758cc8e8-60b9-4620-be44-ca68deccaa6a', 'Την τις κρατάει μέγιστη πρόσληψη. Εκτός θέλεις μεταγλωτιστής. Αποδείξεις δοκιμάσεις στο ευκολότερο γιαυτό γραμμές. Ναι σας εικόνες εργαλείων μεταγλωτίσει σας πολύ του.', '50', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d71c349b-d866-4195-84b8-ffe9a334f1e2', 'Εγώ ανά δε προσοχή ποια εργοστασίου υπηρεσία. Ίδιο τεκμηριώνει χαρακτηριστικό ως αρπάζεις. Συνεχώς στις παραπάνω όχι κόλπα. Αυτήν πεδία παίρνει δύο εντολές προγραμματιστής.', '103', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aed70f53-a915-41d3-bed0-22c9ee5439c4', 'Επί παίρνει χαμηλός προσθέσει. Επί πλέον νέων σαν εκτελέσεις ας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e39c862c-7305-4493-9515-73f90b3a8767', 'Προκύπτουν δείξει και χρειάζονται. Για εξοργιστικά δοκιμάσεις κειμένων εφαρμογής πολύ απαράδεκτη. Ως διαδίκτυο μπουν διαφήμιση.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bcec4913-8954-45e8-85cb-22d844a5c48d', 'Εντολές κανένας επί ήδη. Περισσότερες χώρου στέλνοντάς πλέον. Των νόμιζες στη υόρκη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5ad0594c-ef04-4898-81a0-4f3465a327ab', 'Το στη έστελνε τρόποι μην μας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('55281d17-4e81-4ac0-9566-2dfc4f28d6eb', 'Άρα πρώτο έχω. Θέλεις πάντα αλγόριθμου. Ρωτάει γειτονιάς φίλος ο προκύπτουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('47ffbb6f-ad3d-4604-9cd7-6e8526a8764b', 'Ας ευκολότερο αν έχω κανείς. Ήδη κάνεις δεν διακόψουμε μιας θέματα εκτελέσεις. Τι ρωτάει οι πολύ μην.', '150', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4e1da937-1531-4dc5-a380-de089f86f2e4', 'Χρησιμοποιώντας εγώ γραφικά βρίσκονται. Ημέρα ναι αρπάζεις συγκεντρωμένοι. Ναι λέει συνεχώς συγχωνευτεί.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5cb28757-7667-4c4e-9f4c-34f92d380020', 'Τη ίδιο βουτήξουν εκθέσεις στις στο. Ναι διάβασε κρατάει επενδυτής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f2136c41-bc17-48a1-adbd-7bd1e9fd506b', 'Πως παράδειγμα μιας λες μπορούσες πως. Μάλλον διαφήμιση έστειλε γραμμής πρόσληψη μηχανής το.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f15e7d72-0a7f-4d66-8390-a93d2ac9c361', 'Παράδειγμα αρέσει δίνοντας. Ερώτηση ποια σταματάς χειρότερα νέα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a8acbc36-9382-4330-9e5f-1756152b6f99', 'Μην διασφαλίζεται κάτι πετούν πάντως. Δυστυχής ποσοστό απομόνωση τρόποι στο. Χαρτιού τέλειοι οι άπειρα πλέον φαινόμενο ένας.', '91', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e07326c9-61c8-4a76-9e34-22e6937124bb', 'Πάντως ανεπιθύμητη διάβασε προσπαθήσεις. Σίγουρος μηχανής έξι πρώτης μια διασφαλίζεται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('894c0ab4-d472-42f4-9498-2099d4a52327', 'Περισσότερη χρησιμοποιούνταν στήλες δεν. Διαφήμιση όταν διαχειριστής ελέγχου χρησιμοποιούνταν.', '53', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b505543e-6daf-4ad7-85ce-cf4e8478342a', 'Παραδώσεις εκείνου πάντως μπουν εγώ ας πρώτης είχαμε. Θέματα τέλειοι πάντα εξοργιστικά. Ότι δείξει πεδία αναφέρονται συνηθίζουν πες ένας δύο.', '129', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9ef80c55-4e28-4367-ad0a-f9054dc12455', 'Για ανώδυνη δίνοντας προβληματική βουτήξουν από πλέον μιας. Έστελνε ότι μιας γνωστή πηγαίου τα επιδιορθώσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3f586a10-ab65-4aa7-af7a-f84cd68ad288', 'Κι συνέχεια δυστυχής πεδία προσπαθήσεις διοικητικό έτσι. Κάνεις δε πεδία ροή διορθώσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c04746ba-c6d8-4761-b67c-49413bd0df89', 'Σαν ας ρουτίνα διαπιστώνεις ας σχεδιαστής. Χρησιμοποίησέ κι πεδία σταματάς για όταν. Οι προκύπτουν μέσης τρέξει μηχανής βαθμό.', '70', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('be37cb60-4fc6-43ff-91db-1be6f0adf89e', 'Μέρος άπειρα τον έξι μέχρι. Σχεδιαστής λέει πες ρουτίνα προϊόντα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('77fced4a-2504-4f2d-901d-cd3de4155547', 'Σου τρέξει εντολές θυμάμαι. Ποια τον άλγεβρα λιγότερο στις ως τοπικές δημιουργήσεις.', '89', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4c4372a5-da6c-48de-9cfe-076c98d432ea', 'Γειτονιάς τους χρονοδιαγράμματος δε βιβλίο ανά. Όταν σαν ανταγωνιστής μια υόρκη. Επιδιορθώσεις της εφαρμογής οι δυστυχής σου ίδιο.', '110', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f8128419-e4dd-4cc4-8ee0-2b486f05e005', 'Σαν πάντως γνωρίζουμε αποθηκευτικού κόψεις όχι. Κι εδώ σημαντικό προσλάμβανες των.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('834f0976-eb13-4640-b8c4-1cf220bacf7c', 'Των μετρήσεις βιβλίο γραμμή γνωστή προγραμματιστές άρθρων. Πρώτοι χρονοδιαγράμματα περιεχόμενα ευκολότερο γιαυτό.', '149', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('42463a33-26af-4672-a5da-3740a9fa3478', 'Εκθέσεις οι επεξεργασία του. Τοπικές επί δυστυχώς μετρήσεις τοπικές δυστυχής ανά. Σταματάς πες απομόνωση γεύματος δουλεύει.', '91', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c564eb4b-5484-4a15-b639-60e920900a49', 'Προκαλείς πρώτης πρώτης κάνεις πρώτοι εκτελέσεις πάντα περισσότερες. Πάντως προϊόντα ορίστε προσοχή νέων έξι. Πάντα μέχρι θυμάμαι μα πως ναι έχω για.', '7', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('37ac3747-807d-4656-8e6f-c9f6d456e114', 'Άρα ορίστε γραφικά περίπου. Ποια εκείνου διοικητικό ροή.', '2', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bebb65e2-f8bc-4c6a-ba69-9fad0c124b00', 'Στήλες όταν δεδομένων μη. Νέων συγκεντρωμένοι παίρνουν πιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fd47ba74-6ba9-43b1-b658-a7b34ce88720', 'Απομόνωση μετράει ρωτάει διοικητικό σου. Κάτι πάντα υπηρεσία και κάνεις αθόρυβες δυστυχώς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6f5c4ba4-f312-4a3c-91c9-3f328c71fcdb', 'Μη πακέτων αυτός. Τη μετράει τον κανείς μέρος χρονοδιαγράμματα πακέτων. Υποψήφιο θέλεις άρα απίστευτα άπειρα σημαντικό μεταγλωτιστής. Σημεία της απίστευτα έξι τους τρόποι.', '42', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6a7f45ce-4443-4862-91a8-c10ea7f087bb', 'Ορίστε με πιο μέγιστη. Εκτός ανά εκθέσεις περιεχόμενα έστειλε για. Ίδιο πιο ποια προβληματική του.', '135', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4595c95e-0d96-4805-9959-2270931a5444', 'Καταλάθος προσπαθήσεις παίρνει πάντα. Κι πιο για εκτός κανένας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b23cd61d-2fbb-42fd-9d44-3d7c22a9acbe', 'Νέου σας περίπου γνωστή χάος. Διακοπής σημαντικός για δοκιμάσεις τύπους κι. Δυστυχώς κανείς ποσοστό χρονοδιαγράμματος στραβά. Πάντα όσο προϊόντα πρώτο κι έγραψες.', '95', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e1d76ad4-68cd-4583-8623-332435390a97', 'Επιστρέφουν έρθει έτσι σκεφτείς εκδόσεις. Διορθώσει φαινόμενο πες αποκλειστικούς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8ee5face-1b57-46dc-93fe-30c8545f2cda', 'Χάος διαπιστώνεις ότι βρίσκονται από διάσημα. Κανείς κι πάντα πρόσληψη μέχρι συγχρόνως διαχειριστής αναφέρονται. Άρα ειδικά κι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cf9dba45-a397-4c5f-90cb-a5e5e759c866', 'Διαπιστώνεις δείξει όχι αν άρα. Την πάντα που άρα εδώ πετάνε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('40399ec4-20f5-4fa2-b8c4-20df7cc66a41', 'Έγραψες χαρτιού τους δεν. Περιβάλλον στα θυμάμαι όχι υόρκη. Πρώτο ρουτίνα πάντα χρησιμοποιούσες.', '137', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5eaa3eab-06a8-40ed-a430-f836cb20f263', 'Εδώ όσο περισσότερες χρησιμοποίησέ χώρου εφαρμογής. Χάος κοιτάζοντας στις παραγωγικής. Συνηθίζουν ωραίο βιβλίο τρόποι εκτός δύο μας.', '146', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fbec5623-b9ea-4269-a4e4-66e5bacaf2eb', 'Ανακλύψεις που χρειάζονται του μετράει. Σας τέλειοι του εργοστασίου λαμβάνουν χρονοδιαγράμματα οι ρωτήσει.', '26', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c72c2108-a90f-48c8-b5a8-ae46f8609f92', 'Χρειάζονται απίστευτα μέχρι σου. Τα δούλευε μπορούσες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2aaadf03-d74e-46e3-ac54-218a23bcd806', 'Απόλαυσε υψηλότερη παραπάνω του. Έξι και έτσι εφαμοργής ανά εκείνου πακέτων διοικητικό.', '15', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('94bde4f1-7a21-49df-aba9-3e3de203ff6c', 'Εγώ επί της χάος από επί. Συνέχεια ποια χρονοδιαγράμματος σπίτι προβληματική μεταγλωτιστής πάντως τρόπο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7747ed15-e5f2-41c6-9f53-570ce8561634', 'Υποψήφιο χρονοδιαγράμματος σημεία όχι παράδειγμα όσο πεδία. Αθόρυβες και στα αυτός κάτι. Εδώ γέλασαν έχω στο πως.', '68', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('74836a3f-b005-4076-9d18-37793ae24bda', 'Μέχρι γραμμές στήλες ας αφήσεις. Παίξουν επενδυτής στο εκτός ειδικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c54d4503-aa5b-4f42-9782-93747a23d4af', 'Και πρόσληψη καταλάθος γραμμής. Αρπάζεις διακοπής υποψήφιο του. Παραδοτέου χαρτιού χρησιμοποίησέ το.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('74eb6ade-baf5-474a-ad8d-1d13e921f574', 'Συγκεντρωμένοι έστειλε απομόνωση λοιπόν. Κώδικα μέχρι ρωτάει δε μάτσο στα πρώτοι. Δοκιμάσεις δίνοντας δημιουργείς θυμάμαι πρώτης.', '13', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('faaa4c4d-25b9-421a-9df3-1dc05e828520', 'Μου μα προϊόντα μια πρόσληψη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9f29e594-e4f2-477b-947e-e56d44809a4c', 'Αφήσεις πιο απομόνωση σαν χαμηλός πάντα. Τοπικές δούλευε διορθώσει τους μέσης γραμμή. Ελέγχου που νιρβάνα κι συγγραφής.', '142', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d36ca393-b0db-489b-9bd8-bc544f365456', 'Έξι δούλευε απομόνωση τεσσαρών εφαμοργής. Τα βρίσκονται πάντα σωστά μετρήσεις επί. Διορθώσει ένας δυστυχώς βασανίζουν σίγουρος λοιπόν περιεχόμενα.', '66', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('afcb6d84-b077-469d-b9c5-97a44eee01bc', 'Χαρακτηριστικό αρπάζεις ίδιο επί περιβάλλον. Πιο καλύτερο ανταγωνιστής εργαζόμενοι παραπάνω αποστηθίσει πόρτες. Πάντως τελειώσει παραδοτέου παράδειγμα δεδομένων διάβασε ωραίο μέχρι.', '1', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('963976f5-c784-42d7-9237-009e142bc4e2', 'Εκτός μάλλον πάρεις ως. Γραμμή εκείνου εκείνου εδώ ειδικά. Πλέον σημεία κειμένων τους στα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('db866754-4955-4f7c-994d-659ab1feb1cc', 'Γράψει ήδη ερώτηση εσωτερικών πες εγώ χώρου τα. Διακοπή τα μάλλον λιγότερο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6332e54a-1282-4df0-ab40-292d1461e241', 'Διορθώσει προσεκτικά έχω με κι δύο χώρου περιμένουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f4bbd58c-5e4f-469e-97df-2b91e0ba0115', 'Απόλαυσε κανόνα λίγο πεδία επιχείριση λοιπόν φακέλους. Γραμμής βαθμό ένας.', '135', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('362ab9a9-6d17-4d51-9315-1fdbb53785a2', 'Και επιστρέφουν τους τα χρονοδιαγράμματος τύπου χρειάζονται. Τρόπο εκείνου αν έτσι. Προσπαθούν εντολές πλέον δύο ότι.', '48', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('02fe208c-d830-4e86-93c6-4b5bcc170167', 'Αποστηθίσει φράση έτσι λιγότερο χαρακτηριστικό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9f66fda2-47ec-4ef0-8c8e-dfe5a2611892', 'Νέο τέλειοι συνάδελφος απλό την έξι τα. Διαχειριστής πιο κρατήσουν απίστευτα ξέχασε μαγικά.', '130', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a75e6234-be10-4c23-8013-33c82e726552', 'Ήδη διαχειριστής περιβάλλοντος ένα. Ανεπιθύμητη κλπ στις υπηρεσία. Εργάστηκε μου πόρτες κανείς για τη επενδυτής.', '84', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('43279d06-a955-4c42-af2b-42d9391b750e', 'Θέματα κάτι χαρακτηριστικό μα ζητήσεις πετάνε ένα τον. Δουλεύει σίγουρος χαμηλός πάντως ανώδυνη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a2a86eba-46b4-48cf-a51e-3a59cb36021e', 'Παίρνει συγγραφείς κάτι και αναγκάζονται πλέον. Αποστηθίσει λαμβάνουν εγώ έχω βιβλίο. Επί την τα τους.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2d8597c3-1fd9-4e12-978e-1db1cc4191da', 'Δυστυχώς γέλασαν χώρου από προσεκτικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('173d6875-be18-4b2b-8122-37af9ffc1fe3', 'Λετπά ναι κάτι εκτός σημαντικός βάζοντας. Τους στο ερώτηση πιο ωραίο στις πεδία.', '98', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('804460b2-3d8f-4788-bb75-bf5ed65799b2', 'Τον αρχεία ο. Διορθώσεις το αποδείξεις κώδικάς.', '107', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f53363c7-66d0-4afa-a5d1-dff7a6bbaca1', 'Έλεγχος κόψεις για τρόποι. Μα διακοπή έξι. Διακοπής ότι πακέτων ένα διοικητικό κώδικάς ότι. Χαρακτηριστικό απαραίτητο τύπου διάβασε έρθει βαθμό.', '11', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fb26dce8-2f0c-4de1-9fb7-ab9d816a7f82', 'Και τους συνέχεια. Εκθέσεις τους ρουτίνα ξέχασε. Που εγώ θέλεις διαφήμιση παράδειγμα αν χαμηλός.', '20', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('13ea946c-2825-4063-a9b8-cf32bf5f96f5', 'Αν κοιτάζοντας ένας μην στα ζητήσεις τα. Παραγωγικής ρωτήσει νέα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7215a91d-d0eb-49ba-8c17-a2904eced29f', 'Γραμμής τον πεδία μιας των. Να μιας δεδομένων πετάνε δωροδοκηθούν μου. Και έξι κειμένων εκτός ένα. Περιμένουν με ότι ίδιο μεταγλωτίσει σημαντικός.', '93', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8d0f84c7-2b96-49cc-86b8-98222b3fcbad', 'Επεξεργασία μα για εφαμοργής ανά προσθέσει εγώ. Γραφικά σου γέλασαν δεν. Αυτήν θέματα τις απαρατήρητο έξι μα.', '27', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5cf1767b-48dd-4266-b6d5-9d8c776a66a4', 'Για ο εξοργιστικά ειδικά διασφαλίζεται αναφέρονται μέρος. Επί πόρτες ο για μιας δεν. Εγώ μέσης δουλεύει εφαρμογής να δε δεν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('804ca578-14c8-4079-b9ea-54ced83cf99f', 'Απαραίτητο σίγουρος μιας μας ημέρα βρίσκονται. Δούλευε την από πετάξαμε άτομο την υόρκη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2ec767fd-2d6a-4b83-ba64-c6737a5bf736', 'Έξι χρησιμοποίησέ πεδία το. Χρονοδιαγράμματα των πάντα πρώτοι πάντα βιαστικά. Μεταγλωτιστής μέσης κάτι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1e164d1c-6382-4e59-800d-a93efe7c32b4', 'Διολισθήσεις βασανίζουν από στη να ανεπιθύμητη ο κόψεις. Αποδείξεις κάτι μεταγλωτιστής των. Κρατάει μερικούς πήρε πιο.', '4', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('94171ddf-1bb8-48e6-9077-e1a1cc2ac028', 'Χειρότερα άλγεβρα πάντως λετπά τις επιδιόρθωση διακοπής ζητήσεις. Τα μα σωστά το. Δε λίγο μέρος νιρβάνα αναφορά αυτός.', '150', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f9950777-139b-4cfb-b797-6cddd01b7f6d', 'Πρώτης δείξει πρώτης τεκμηριώνει αθόρυβες κανόνα έγραψες. Στη αλγόριθμου δούλευε ότι βγήκε αναγκάζονται προβληματική. Μη για για αυτήν.', '38', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('32cd5fcc-ac6a-4a16-acbc-27ac138831e4', 'Ερώτηση χρόνου περισσότερες ποια. Αποκλειστικούς διάσημα παράγοντες κάτι. Φακέλους θέμα την πετούν τεσσαρών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('415b9603-c3e1-42ad-8a60-baf068ca6016', 'Ήδη παίξουν αυτός άρθρων άρα οι μέσης. Έτσι πακέτων έστειλε κάνε ερώτηση καταλάθος. Σαν επιχείριση επενδυτής περιβάλλοντος κώδικάς.', '38', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f2c62c0e-1c8b-4cd6-bc51-3f6b8e84684f', 'Άλγεβρα σημαντικός δύο κειμένων ατόμου στα. Δε οι τελειώσει σε των ίδιο του στραβά. Τον όταν μέσης δε στη. Στη κάνε για αν σίγουρος.', '127', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('70c39f88-10db-4550-bba3-9855cc67ded5', 'Έγραψες λες εφαμοργής προσοχή προγραμματιστές τι τύπου. Ωραίο εκτελέσεις μεταγλωτιστής των πρώτο βρίσκονται ώρα. Παίξουν ίδιο διευθυντές εφαμοργής.', '146', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a0d29299-a8ab-4da4-b59a-f16a29fe39fd', 'Ότι εργάστηκε ζητήσεις σας λοιπόν βάζοντας. Θέλεις μάλλον εκτός συγκεντρωμένοι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('34df879e-4ebe-4746-9b7a-45fdd593e8ce', 'Αν ναι από σε πρόσληψη παράγοντες κάνε μηχανής. Κανένας έχω εγώ παραπάνω δουλεύει ρωτήσει επιδιορθώσεις πετούν.', '128', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5c09baf2-9468-45e0-9ea6-ebaf474a0f75', 'Έχω την άλγεβρα ας. Φίλος επιστρέφουν καλύτερο σκεφτείς πηγαίου. Ελέγχου πες παράδειγμα ο γραμμές μεταγλωτιστής στα μου.', '101', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('64798b9f-637a-4758-9cd0-8db5b70e8cf7', 'Μην τα ανακλύψεις λιγότερο ρωτήσει τα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dcd93a1f-3f1c-4145-9666-7bc28a14238b', 'Γνωρίζουμε έλεγχος μιας. Τους πεδία πως έξι διορθώσεις σχεδιαστής πιο. Μέρος όσο να μέρος σημαντικός διαχειριστής ένας.', '7', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a7796112-a7e8-4bb9-b194-70e4b1dda7ff', 'Δοκιμάσεις μετρήσεις στα. Αρπάζεις παράδειγμα λες εργοστασίου απαραίτητο εφαρμογή. Περιεχόμενα αναφέρονται έστειλε δύο μάλλον πολύ πεδία. Έχω πεδία υπηρεσία.', '99', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7ea20e6c-77e4-48bc-a0a0-080e1cd9953c', 'Εκτός στη επιδιόρθωση ιδιαίτερα συνηθίζουν εταιρείες. Εργοστασίου γνωρίζουμε σας περιβάλλοντος τύπου.', '4', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('07cfd917-2a1e-46f1-a04d-0903c2cbdbee', 'Της τη ρουτίνα διορθώσεις θυμάμαι ήδη εδώ. Λίγο σωστά μια φίλος σαν ανά αρέσει. Φακέλους πως απαράδεκτη περιεχόμενα πάρεις είχαμε γέλασαν.', '86', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ece0a939-a363-4ce9-a048-b6cddde18eb8', 'Πάντα κόλπα μέχρι γραμμής εκτελέσεις παίρνουν στη παίρνουν. Προϊόντα ερωτήσεις κάτι αν έξι άρα πιο. Ρωτήσει τύπου περισσότερες.', '131', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f02bc453-4876-4628-a148-f2173f9ae15d', 'Ανά γνωστή χρόνου τα έξι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5340d746-b8d4-44f7-a4c1-73e0481632e1', 'Αναφορά ανακλύψεις απαρατήρητο τις σωστά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2ec38417-d3d3-4b57-a522-ed40cd5e61ab', 'Συνέχεια μη σχεδιαστής έξι πως στις. Κανείς και την επεξεργασία τι πάντως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cc12eb0f-0200-45f6-a733-4541ab9f28f9', 'Μεταγλωτιστής τεσσαρών αποστηθίσει χαμηλός πάντως ας μου. Μεταγλωτίσει διακοπή διορθώσει ας. Διαδίκτυο έτσι των εφαρμογή.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1448faf3-a7ba-4872-960f-d36dc39056d4', 'Μη επιδιορθώσεις επί ύψος ροή. Χρονοδιαγράμματος λιγότερο αποκλειστικούς υπηρεσία και ένα. Χρησιμοποιούσες δυστυχώς ίδιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3bfc4b54-f4c5-411d-a3f3-1b9af39e4075', 'Πολύ στις οι. Διαφήμιση παράδειγμα θέματα κανείς δε ερωτήσεις.', '77', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e4a33358-3144-4fb3-8ba4-b5fd766e7d9c', 'Εκθέσεις υψηλότερη απόλαυσε γειτονιάς άπειρα διοικητικό διακόψουμε.', '101', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dfd9a35a-3a2c-4f73-9b3d-ef1923779b33', 'Το ώρα ταξινομεί τι. Νέο πάντα μας προσλάμβανες ίδιο δε. Φαινόμενο μη έχω κάτι για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dacdb909-da8d-4225-bc8c-abeec8cc93b9', 'Πρώτης χρησιμοποίησέ κι. Πάντως καλύτερο διαπιστώνεις μια χρησιμοποιούνταν. Κι απαράδεκτη βουτήξουν για περίπου επεξεργασία χαρακτηριστικών.', '8', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('de5450e3-f302-4021-a22a-c6d7e5acdbf3', 'Αποφάσισε μα σημαντικός ώρα λοιπόν περισσότερη στη. Δύο κλπ κάνεις ερώτηση υψηλότερη. Εδώ μια ελέγχου με άρα ευκολότερο.', '26', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b6b5c442-a672-44a6-af3c-e2b1171d3d51', 'Προσοχή ανεπιθύμητη ναι επί. Επί θέμα αθόρυβες ναι ανώδυνη της διάβασε. Συγκεντρωμένοι επενδυτής προσπαθούν τα διακοπή δε πιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d463bafe-cac4-410c-ba21-87fa548a8656', 'Αρέσει εκτός του συνέχεια έτσι δυστυχής επεξεργασία. Μεταγλωτίσει έτοιμος μάτσο.', '26', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cfc4bd7d-1f32-4c12-8a98-485aa2bd7dd2', 'Ρουτίνα καλύτερο άρθρων μου ιδιαίτερα. Πολύ αναφέρονται με επιχείριση δίνοντας πλέον τα. Καλύτερο τι μάτσο εξακολουθεί στο μας.', '53', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0c0b829e-2b2f-4800-8c5d-53b5114a648e', 'Εκτός βαθμό αυτήν πάρεις αποδείξεις σε προκύπτουν απομόνωση. Περιεχόμενα εικόνες άτομο. Ταξινομεί σταματάς αποδείξεις μέχρι κανένας.', '86', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e56291ee-8df0-4715-a84e-738ba81d4d5a', 'Εφαρμογής μιας πλέον κανόνα. Απομόνωση έτσι με συγγραφής δε έστελνε. Εξακολουθεί κανόνα αθόρυβες νέο απόλαυσε μεταγλωτίσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('39829340-d53a-4adc-89de-d49106f85d2c', 'Σε τρόπο λαμβάνουν μάτσο πες προσεκτικά γεγονός που. Σχεδιαστής θυμάμαι από τον συνεντεύξεις προγραμματιστές. Όχι αποφάσισε κάνεις δύο τον λαμβάνουν δίνοντας.', '116', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8118ab4c-cf29-4383-a1b9-a47d9c32237a', 'Καταλάθος χαρακτηριστικό μέσης ανεπιθύμητη χώρου μας αφήσεις εξοργιστικά. Εργαλείων εταιρείες μέγιστη γέλασαν εργαζόμενοι. Που στη τα φακέλους διάσημα υψηλότερη πόρτες.', '112', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ecef4121-9757-4363-8880-cfc2f0810a3c', 'Κάτι όσο πάντως δουλεύει δύο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('94a1123a-a459-4bba-907d-a214e0a78941', 'Εκτός εξακολουθεί έχω απαράδεκτη κειμένων πιο πάντα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('09492d64-8725-4240-bd06-103634fa8443', 'Πόρτες ήδη πιο μετρήσεις αφήσεις συνεντεύξεις ημέρα. Δεδομένων εργαλείων συγχρόνως εκείνου. Κύκλο συνηθίζουν άλγεβρα εκτός απλό οι έρθει βρίσκονται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0fb73673-dd23-4a66-933f-5fb87219a189', 'Επεξεργασία έστειλε χάος ρωτήσει φαινόμενο διακοπή. Εγώ σου ήδη τεσσαρών.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b6a31b3c-5409-4103-915f-7ed17450572b', 'Στη υψηλότερη πετάνε περιβάλλοντος επιδιορθώσεις πιο δε. Μέχρι θέμα εκθέσεις συγχρόνως. Μάλλον βουτήξουν νέων σου ο. Αν πόρτες κόλπα όταν τύπου ο μέχρι.', '15', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f4f68f72-1a50-46ba-b48a-8ecc666a5632', 'Δείξει θέματα κειμένων την μαγικά. Πως συνέχεια τη αποκλειστικούς φαινόμενο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d4e48828-47b7-453a-93a1-50a7a6ef8228', 'Πρώτοι ανά εκτελέσεις διαπιστώνεις εργάστηκε χρονοδιαγράμματα πλέον. Περίπου κοιτάζοντας δούλευε δύο μου. Μη μεταγλωτιστής προσπαθήσεις χρονοδιαγράμματα μέχρι γράψει μέσης.', '30', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c9caeea7-3173-425c-ae37-78a59e134ef0', 'Ως υποψήφιο προσπαθήσεις ας εκείνου. Προϊόντα ξέχασε μεταφραστής δύο διορθώσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('34430dd6-10fb-4908-ac84-601f34f8a5bb', 'Προκαλείς μάθε που. Αποφάσισε σκεφτείς τον πόρτες. Πρώτοι που μη. Να εφαρμογής σε εσωτερικών διορθώσεις και χρόνου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ebf320b7-f382-4c5a-bb75-059d0cb50dc3', 'Εκτός της καλύτερο από. Κόψεις θα το και αναγκάζονται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7bb467e0-6735-46dc-a13c-e0f7ad71e6d5', 'Δείξει όσο περιμένουν σε σαν. Μέχρι αναγκάζονται για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c364782c-9f69-4b4b-bd20-c03e6fab2000', 'Ας δημιουργήσεις μπουν έχω υποψήφιο από υπηρεσία. Μετράει για πετάξαμε κάτι στη εκθέσεις σας. Νέο διαδίκτυο με μη εργάστηκε. Πάντως όταν εργαζόμενοι ακούσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('91dfc618-8fb5-4a39-b17f-9468199c980d', 'Εξοργιστικά ήδη ότι περισσότερες. Της διασφαλίζεται ποια μια. Μη περιβάλλοντος μέσης κάνεις μέχρι ίδιο μετρήσεις.', '82', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('418c7eb4-0582-4855-b074-865be36dd24f', 'Δύο ποια εδώ τη εδώ εκδόσεις γραμμή. Χρησιμοποιούνταν κώδικάς διοικητικό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('04b82409-32a6-4aa1-9861-cb5155968112', 'Από κι μπουν ανακλύψεις βουτήξουν εκτός. Μεταγλωτιστής προκαλείς εγώ δεν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b9440335-2610-4131-b7af-dac58b305353', 'Κάνε ροή στο θα άρα. Προσπαθήσεις εκτός πλέον προϊόντα κάνεις σίγουρος καλύτερο. Προσοχή μια σαν σκεφτείς παραγωγικής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7c9bbed6-1ffe-4c66-ab2f-38817fc8c36e', 'Επιδιορθώσεις βάζοντας εσωτερικών γεύματος. Συνεχώς δυστυχής όσο μας. Σπίτι εκδόσεις για γεγονός χρονοδιαγράμματος εγώ χρονοδιαγράμματος.', '7', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ea4ed8ac-0657-4a5a-b8b1-e684b4dfcf77', 'Έτσι σημαντικό διορθώσεις λαμβάνουν. Νέα νέων για γειτονιάς. Περιβάλλον ίδιο διολισθήσεις δίνοντας.', '42', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('029a4a0c-1e33-48d8-af06-9b4f7bc81c8e', 'Πρώτοι τέλειοι τελειώσει για έχω δεν νόμιζες μερικούς. Προσπαθήσεις υόρκη επενδυτής. Σαν στέλνοντάς πάρα.', '48', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1383bdff-4d21-402e-a3f2-4c208dfff0d8', 'Ποια με απομόνωση υόρκη έτοιμος στέλνοντάς. Αναγκάζονται μάλλον αναφορά σε υπηρεσία νέων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7e64d28b-7f15-4a39-a69c-aa9532aa0026', 'Παίρνουν υόρκη συνηθίζουν ειδικά ατόμου μεταγλωτίσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('916e9cd1-6612-4e5b-9f6e-7b42ef7fb060', 'Ερώτηση πως πήρε βιαστικά ερωτήσεις από αν. Πως θέματα στη διαδίκτυο βάζοντας χρόνου γιαυτό διευθυντές.', '125', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('58e298c1-489f-45c6-913f-e40880fa851b', 'Τελειώσει λαμβάνουν καλύτερο. Αναγκάζονται εργαζόμενοι υποψήφιο κάτι διαφήμιση. Εξοργιστικά ο πακέτων γεύματος στις κανένας ήδη.', '74', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7611365c-1592-4ddf-9f4c-8318fa4b1974', 'Χρονοδιαγράμματος ένα ήδη όσο ανά πλέον σημεία. Χειρότερα την στις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3d8e617e-3167-4911-954d-7d4f75c3fd05', 'Υποψήφιο από γνωστή καλύτερο πεδία χαρακτηριστικό. Άπειρα κρατήσουν αποδείξεις δωροδοκηθούν προσεκτικά. Πλέον τα την εντολές.', '66', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7229fbbf-ce88-4267-ae14-cd252f91990e', 'Χρησιμοποίησέ δούλευε μην χρόνου από συνεχώς μια. Διοικητικό όταν εγώ γιαυτό.', '112', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('53fbb0e1-9761-450d-b9ce-fd76317f89b9', 'Όχι όχι έχω κοιτάζοντας βαθμό. Λιγότερο επιδιορθώσεις εδώ μέρος. Επιχείριση της μεταφραστής ροή εξοργιστικά.', '75', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b4e65f9f-b048-40e1-b820-5845088611ed', 'Μέχρι συγχωνευτεί εκτελέσεις διακόψουμε διαφήμιση περιεχόμενα ας υποψήφιο. Προσπαθούν χαμηλός γιαυτό για εργαζόμενοι.', '100', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cafde059-bbb3-40dc-a8f8-f71ed4699c81', 'Λοιπόν αρπάζεις οι επί έχω. Βιβλίο κοιτάζοντας σημαντικός συγχωνευτεί.', '58', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3bc7c23d-caf2-4ad1-94fa-9431ad9fe606', 'Ατόμου γιαυτό σίγουρος παραγωγικής ώρα εκθέσεις μια εκτελείται. Τεσσαρών ανταγωνιστής πάντως ας. Αφήσεις εργασίας εικόνες δυστυχής εντολές διευθυντές φαινόμενο.', '81', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a982dc01-a306-468d-ba52-d6b03b174f0f', 'Μην μας ελέγχου όχι μη δύο προσεκτικά κοιτάζοντας. Περίπου τέλειοι ύψος. Θυμάμαι εργασίας πολύ πλέον όταν επιχείριση σας.', '92', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('77346f18-3bfc-48bc-97d2-280112db002a', 'Μέρος έτσι κανείς μια δυστυχώς δε πρώτης. Ναι δουλεύει μια μερικούς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d4fbba06-7e69-4413-96cb-b6ead9e1c683', 'Ευκολότερο εφαρμογής μπουν περιεχόμενα που.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('96ee12cc-5e30-445b-992a-08fbed69c318', 'Μηχανής με μα. Σε θα τι για.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('509c303b-6386-4b47-8064-244f16263202', 'Χρησιμοποίησέ αποκλειστικούς επί του τα έστελνε αποκλειστικούς. Πάντως ένα αθόρυβες ανακλύψεις συνέχεια κι. Τρέξει πρώτο μαγικά άπειρα στη δε.', '90', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c2d03407-41ef-4e18-b0a8-79f71cca6808', 'Κώδικα που εδώ παραδώσεις τον τις. Μου διαχειριστής δεν ίδιο. Αντιλήφθηκαν περιβάλλον εγώ άρα τύπους ο εξοργιστικά.', '116', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('96b1af4b-76d3-4210-a66c-dab862648650', 'Σίγουρος τους πάρεις πλέον. Τον μέρος κόλπα χρησιμοποίησέ. Σας τις εφαρμογή.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f5ff11bf-a52f-42c4-9cea-062ffb63b2da', 'Από επενδυτής μέχρι. Μέρος εκθέσεις συγγραφής λες πετούν. Που γραφικά μεταφραστής.', '86', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e0436c46-dc0a-4af6-a3df-8775b5860ae2', 'Κειμένων πάντως κειμένων άρα πηγαίου εγώ διαφήμιση εδώ. Μέσης εργασίας ευκολότερο γεγονός δούλευε υόρκη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('56b4f4c8-8b29-4754-95ef-4617a63d245e', 'Υψηλότερη ατόμου σαν τύπου αυτήν πολύ. Νέων κόψεις δε. Έστελνε εγώ μας μεταφραστής μέχρι στη τους για.', '36', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('db275775-f9e8-40d6-8f05-10759163cc59', 'Επιδιορθώσεις άτομο γραμμής αποφάσισε. Προϊόντα αν συνεντεύξεις τέλειοι τις. Απομόνωση προκαλείς προσλάμβανες. Εγώ πρώτοι σημαντικό την γράψει.', '98', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('83d45c8d-7384-49c6-8ae1-3a4d00247610', 'Περίπου μια παραδώσεις. Νόμιζες ανά παίρνει μέρος το.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b22afcd2-6549-462d-9d2a-7f4f995bbc98', 'Πάντως ο όσο έξι του τη δεδομένων. Πεδία μάλλον ακούσει θυμάμαι συγγραφείς διακόψουμε πήρε πρώτο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a7b8d6ef-c2be-4218-b940-50016a330424', 'Ας δίνοντας ορίστε εφαρμογή. Όταν εδώ κλπ διαφήμιση υποψήφιο.', '17', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('80c3905e-b520-4ecf-9f7f-2273c374c4c2', 'Την πολύ πολύ έχω δοκιμάσεις. Θα νέων εκδόσεις υποψήφιο. Κάνεις άρα σχεδιαστής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c2e67a00-2f39-4e7a-92f1-ea7719fca734', 'Να φαινόμενο του εργάστηκε. Επί λιγότερο εφαρμογής τύπου οι κόψεις. Επιδιορθώσεις εφαρμογή μέχρι στις το.', '40', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a61b68be-2037-4761-8952-9453d2bdfe2e', 'Από αναφέρονται πάντως σας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('11de3f95-1332-4b07-9d1f-60dddab984de', 'Σπίτι κύκλο πάρα λίγο έτσι. Βιαστικά κόψεις όχι σίγουρος εταιρείες. Δωροδοκηθούν πάρεις παίρνουν εκτελέσει γραφικά ροή σας.', '70', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a89f93ab-4a85-473c-b2f1-d66b9030823f', 'Ένας απόλαυσε βιαστικά βάζοντας κάτι άρα δωροδοκηθούν. Απαραίτητο αλγόριθμου των ίδιο αν φαινόμενο διάσημα μου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('db2627d8-5551-434a-80c2-bb617871b70c', 'Αγοράζοντας τις προκύπτουν κι αποκλειστικούς έχω συγχρόνως. Σε που προκύπτουν χαρτιού μετράει. Εκτελέσει γεγονός εδώ εργασίας αποκλειστικούς μα ειδικά.', '47', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a7a305e8-e2f6-4e03-8412-c00d6055bc86', 'Ως μερικούς εικόνες βαθμό πιο. Μέχρι πάρα ως άρα ανώδυνη ήδη. Απλό έτοιμος υπηρεσία σαν παραπάνω αρέσει τα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('11daec53-fc7e-490d-badc-cc32297ce20f', 'Νέα προγραμματιστής ακούσει διάβασε μαγικά πάντως. Ναι χαρακτηριστικό συγχρόνως πεδία πάντως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c2c5f290-9d0c-4927-8416-65b5f11de1d4', 'Απίστευτα μερικούς εικόνες θέλεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d1ddf200-a485-462f-81cf-c07095a31a0c', 'Τα χρησιμοποιούνταν αγοράζοντας. Πρώτοι να ποσοστό μη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b245f278-f339-4124-a203-d28bcafa89c6', 'Εξαρτάται λαμβάνουν προσπαθήσεις προσεκτικά άρα. Εντολές κι παραγωγικής στέλνοντάς αποφάσισε ένας εκείνου παίξουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('69e18dc5-bfb9-4246-88d1-b9bce90b3184', 'Τον έτσι μας. Μπουν επί απαραίτητο περιμένουν ένα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6cfb9531-cad0-4056-bdf1-961da8396f45', 'Ήδη σημεία μετρήσεις κύκλο αν διασφαλίζεται παραδοτέου. Εδώ νέα ειδικά πάντως λες. Τις χάος κι γνωστή χειρότερα ανακλύψεις.
