INSERT INTO media (media_id, path, description) VALUES ('1', '/media/images/image_et.jpeg', 'Για το στα ανώδυνη. Χρειάζονται ανά μεταγλωτιστής μη.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('1', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('2', '/media/images/image_ipsa.png', 'Μερικούς μια φίλος έξι προσπαθούν. Από επί κάνεις και.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('2', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('3', '/media/images/image_sunt.png', 'Βαθμό προσπαθήσεις από τεκμηριώνει δίνοντας. Πρόσληψη όταν μέχρι πιο ημέρα κανόνα.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('3', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('4', '/media/images/image_vel.jpg', 'Προγραμματιστές πάντα εκτελέσεις εκθέσεις. Γραφικά προγραμματιστές ότι πολύ γέλασαν.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('4', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('5', '/media/images/image_ea.jpg', 'Πρώτοι άλγεβρα γνωρίζουμε το επί. Χρονοδιαγράμματα εφαρμογή εφαρμογής των. Κανείς μεταγλωτίσει δε λες στο πετάνε.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('5', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('6', '/media/images/image_distinctio.jpg', 'Πρώτης έξι τρόποι αφήσεις σε κοιτάζοντας. Μη άρα ατόμου ανταγωνιστής επί γέλασαν.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('6', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('7', '/media/images/image_voluptate.png', 'Λαμβάνουν εντολές αντιλήφθηκαν διασφαλίζεται δείξει. Τέλειοι περιβάλλοντος για κρατάει γέλασαν επί.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('7', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('8', '/media/images/image_inventore.jpg', 'Αγοράζοντας γραμμή πρώτης ημέρα μπορούσες. Χρησιμοποιούνταν χρονοδιαγράμματα στέλνοντάς περιβάλλον. Αρπάζεις των υψηλότερη μάλλον πιο υποψήφιο συγγραφής μεταγλωτιστής.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('8', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('9', '/media/images/image_dolorem.jpg', 'Αφήσεις δύο σας έτοιμος αναφορά ίδιο τύπους. Δύο κώδικάς αποκλειστικούς πήρε ευκολότερο μέχρι πες. Μέχρι έστελνε αυτός σωστά μπορούσες προκύπτουν κόψεις αναφέρονται.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('9', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('10', '/media/images/image_aspernatur.jpg', 'Άρθρων πάντως τα σου. Χώρου διορθώσει στις πιο ορίστε όχι ναι. Διαφήμιση άρα έχω εκτός.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('10', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('11', '/media/images/image_ullam.jpeg', 'Την για πρόσληψη πες. Σωστά υποψήφιο δημιουργήσεις συγχωνευτεί.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('11', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('12', '/media/images/image_deleniti.jpg', 'Ροή εξοργιστικά μου εικόνες πετάνε εφαρμογή μαγικά. Βάζοντας πόρτες έλεγχος άπειρα πήρε προσεκτικά τους. Βιβλίο κύκλο μας περισσότερες.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('12', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('13', '/media/images/image_dignissimos.jpg', 'Εξακολουθεί πλέον σίγουρος. Μα χρονοδιαγράμματα κάτι ιδιαίτερα.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('13', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('14', '/media/images/image_voluptate.png', 'Στο ορίστε πρώτοι και αποδείξεις κάνε πρώτης πως. Αν κρατάει πάντως εργαζόμενοι αναγκάζονται μα. Τελειώσει μην διάβασε ότι.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('14', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('15', '/media/images/image_explicabo.jpg', 'Μετράει σημαντικό διευθυντές έξι εργασίας έχω παραδώσεις. Αν αγοράζοντας απίστευτα τεκμηριώνει λαμβάνουν.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('15', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('16', '/media/images/image_praesentium.jpeg', 'Γεύματος πάντως υόρκη όχι τοπικές συγχρόνως μάτσο κώδικάς.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('16', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('17', '/media/images/image_non.jpg', 'Μέρος έστελνε παραπάνω αθόρυβες. Τρόποι ευκολότερο γέλασαν λαμβάνουν ένας πάντως του. Αποδείξεις ίδιο ναι. Πολύ δύο θέμα μας.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('17', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('18', '/media/images/image_quae.jpeg', 'Υποψήφιο συγχωνευτεί μέγιστη θα ακούσει κι τελειώσει σπίτι. Στις στο φακέλους δύο ποια εξακολουθεί.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('18', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('19', '/media/images/image_nobis.png', 'Μέγιστη δύο περιεχόμενα για. Ίδιο παραπάνω αγοράζοντας αθόρυβες εκείνου χρησιμοποιώντας.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('19', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('20', '/media/images/image_quisquam.jpg', 'Πρώτο πρόσληψη πες θα μην. Αποδείξεις ξέχασε απόλαυσε σταματάς προσλάμβανες άπειρα.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('20', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('21', '/media/images/image_quidem.jpg', 'Τύπου χρονοδιαγράμματα σας γραμμή δεδομένων πάρα τον. Άρθρων γεγονός γιαυτό του. Λίγο ήδη ερωτήσεις στα χαρακτηριστικό ροή επεξεργασία αναγκάζονται.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('21', 'doctor_id');
INSERT INTO media (media_id, path, description) VALUES ('22', '/media/images/image_earum.jpg', 'Όταν εικόνες ημέρα οι δημιουργια. Υποψήφιο λίγο μάλλον επιστρέφουν δυστυχώς εκτός. Απόλαυσε άρα γέλασαν. Ένα τύπου ανά απόλαυσε διάσημα μια.
