INSERT INTO media (media_id, path, description) VALUES ('23', '/media/images/image_enim.png', 'Μεταφραστής κανείς εκτός εκτός. Εκτός το ανεπιθύμητη. Διοικητικό υψηλότερη έστειλε επιδιόρθωση παίξουν άρα.
