INSERT INTO media (media_id, path, description) VALUES ('158', '/media/images/image_tempore.jpeg', 'Εκείνου τρέξει λαμβάνουν ευκολότερο μεταγλωτίσει μεταγλωτίσει πετάξαμε. Σκεφτείς μέχρι αν εξοργιστικά αυτός δεδομένων επιχείριση. Αρχεία απόλαυσε εφαρμογή αποθηκευτικού πάρα πως.');
