INSERT INTO media (media_id, path, description) VALUES ('161', '/media/images/image_sequi.jpeg', 'Μεταγλωτιστής ποια μέχρι επιδιόρθωση διαπιστώνεις εργάστηκε. Αρπάζεις χρονοδιαγράμματα μέγιστη των ρωτάει. Αποδείξεις γεγονός μη. Χαμηλός εδώ μας επιδιορθώσεις το.');
