INSERT INTO media (media_id, path, description) VALUES ('613', '/media/images/image_dolorum.jpeg', 'Διάσημα ανώδυνη νέα ανά. Μου τα πιο αποθηκευτικού αρχεία για. Μέχρι ίδιο τεσσαρών διακόψουμε στα περισσότερες.');
