INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '116317', '1992-07-30 00:00:00', '1992-09-24 00:00:00', 'Διαπιστώνεις λαμβάνουν εκθέσεις. Πακέτων στα ανεπιθύμητη. Εκτός από υπηρεσία αναφορά όχι χάος διαπιστώνεις.', 'Διολισθήσεις γράψει μέρος παίρνει. Σχεδιαστής θέμα σε παράδειγμα τέλειοι δύο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('2', '1004904318', '1009723276');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('2', '25844', '2012-07-06 00:00:00', '2012-07-26 00:00:00', 'Την επί χρησιμοποιούσες υποψήφιο γραφικά προβληματική. Χρησιμοποιούνταν πρώτης ακούσει κρατάει αναγκάζονται. Καλύτερο πολύ προϊόντα αποστηθίσει ποια επιδιορθώσεις.', 'Παραδώσεις μη απόλαυσε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('3', '1905434261', '1012692076');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('3', '73707', '1951-09-18 00:00:00', '1951-10-29 00:00:00', 'Ανεπιθύμητη αρέσει προσπαθούν δύο επιχείριση. Έτοιμος χώρου τα τη γιαυτό. Πηγαίου σου ήδη του.
