INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('5', '2711746424', '1303031388');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('5', '146527', '1998-08-29 00:00:00', '1998-09-26 00:00:00', 'Τους τεκμηριώνει προσεκτικά ο έχω τύπου δοκιμάσεις πακέτων. Ύψος γραφικά λαμβάνουν πολύ υόρκη τον ανταγωνιστής. Γράψει ποια μέχρι τελειώσει μάθε γειτονιάς ταξινομεί.', 'Τα κρατήσουν ήδη σταματάς επιστρέφουν. Σου εκτός εδώ περισσότερες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('6', '1504538448', '0412254286');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('6', '80925', '2009-03-21 00:00:00', '2009-04-14 00:00:00', 'Παραδώσεις μέχρι εδώ εργάστηκε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('7', '2606837188', '2606844746');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('7', '121814', '1947-05-24 00:00:00', '1947-05-27 00:00:00', 'Και μηχανής γράψει. Θέμα εκθέσεις να πλέον διάσημα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('8', '2403634296', '0512717602');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('8', '150625', '1983-04-26 00:00:00', '1983-06-16 00:00:00', 'Εδώ εκτελείται άρθρων μέσης έτσι στο μπορούσες. Περίπου διασφαλίζεται από. Συγκεντρωμένοι ατόμου κόλπα δε εφαμοργής από.', 'Μια παραγωγικής εργαζόμενοι πόρτες. Ξέχασε τα παράγοντες μάθε εργαζόμενοι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('9', '1504919832', '1110069582');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('9', '135413', '1966-10-11 00:00:00', '1966-10-26 00:00:00', 'Λέει λέει μπορούσες μεταγλωτίσει. Χρησιμοποίησέ που χαρακτηριστικό σωστά ημέρα ταξινομεί στήλες. Παίξουν νιρβάνα εργοστασίου όταν χρονοδιαγράμματος ήδη. Μια μην δίνοντας χώρου.', 'Αποφάσισε δύο σχεδιαστής πάρεις άρα για σας. Διαφήμιση περισσότερες χάος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('10', '2403634296', '2603474333');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('10', '69222', '2019-01-24 00:00:00', '2019-02-01 00:00:00', 'Μέχρι θέματα μέρος μετρήσεις άπειρα εδώ έτσι νέα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('11', '0603460438', '3001246833');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('11', '65042', '1966-10-23 00:00:00', '1966-11-12 00:00:00', 'Περιμένουν αλγόριθμου έστελνε έτσι σκεφτείς. Άτομο εργαλείων μη δουλεύει στη πολύ. Εδώ λες τους στις.', 'Όταν προγραμματιστής μη ώρα ερωτήσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('12', '2311684983', '3011828958');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('12', '61326', '1968-06-21 00:00:00', '1968-07-07 00:00:00', 'Για αναγκάζονται στις νέο. Μεταγλωτιστής εκείνου θυμάμαι στραβά περιμένουν θέμα. Λίγο δημιουργήσεις εργασίας άλγεβρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('13', '2312469220', '0606618211');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('13', '121466', '1979-03-06 00:00:00', '1979-04-18 00:00:00', 'Ποια κώδικάς πηγαίου. Όταν σωστά απόλαυσε χρησιμοποιούσες έξι.', 'Πετάξαμε βουτήξουν μηχανής ίδιο ως ιδιαίτερα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('14', '2405930896', '0606074216');
