INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('16', '0502786206', '1012692076');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('16', '90316', '1940-05-18 00:00:00', '1940-06-28 00:00:00', 'Συνέχεια επιχείριση κανένας αν ο είχαμε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('17', '0111535131', '0610232616');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('17', '54221', '1983-10-01 00:00:00', '1983-11-27 00:00:00', 'Έστειλε σαν στη συγχωνευτεί όσο μα απαραίτητο. Κώδικάς στραβά παράδειγμα ανεπιθύμητη. Μα ταξινομεί εταιρείες απαρατήρητο ίδιο επί.', 'Τέλειοι επιστρέφουν τεκμηριώνει προβληματική μιας κι αντιλήφθηκαν κι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('18', '2312590646', '1403180516');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('18', '51483', '1945-04-09 00:00:00', '1945-04-24 00:00:00', 'Μια για οι σε. Διαδίκτυο εργαλείων δωροδοκηθούν κι λες μας. Μέρος υπηρεσία συγκεντρωμένοι βάζοντας άρθρων ως πιο εφαρμογής.', 'Βασανίζουν στη αν βιβλίο. Ρουτίνα συγγραφής νιρβάνα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('19', '3005652478', '0401138022');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('19', '152478', '1977-06-06 00:00:00', '1977-06-25 00:00:00', 'Έχω κύκλο μάτσο περιμένουν μέχρι ερωτήσεις. Μην στη κώδικα εκτελέσεις βουτήξουν δούλευε πιο. Πάντα εφαρμογή και της κώδικα τα και.', 'Μεταγλωτίσει τα να τους εικόνες έλεγχος πεδία.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('20', '1810717683', '1608646023');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('20', '123609', '1978-04-28 00:00:00', '1978-05-19 00:00:00', 'Πήρε μα ένας οι θυμάμαι. Ξέχασε γιαυτό εκτός που. Παίξουν γέλασαν διαφήμιση έστελνε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('21', '1001924992', '0308427033');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('21', '99348', '2023-04-21 00:00:00', '2023-06-11 00:00:00', 'Στήλες ήδη γνωρίζουμε. Σαν ο εδώ παράδειγμα αποκλειστικούς. Μην γράψει χαρακτηριστικών μας προγραμματιστής δεδομένων δούλευε. Θέμα κειμένων φακέλους.', 'Δίνοντας δείξει χρησιμοποιούνταν έτσι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('22', '0207544142', '1610925777');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('22', '146560', '2025-07-26 00:00:00', '2025-08-28 00:00:00', 'Δυστυχής μηχανής ρωτήσει ωραίο διαχειριστής παίρνει συνάδελφος άρθρων. Δύο διαπιστώνεις διακοπή δοκιμάσεις κανόνα σε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('23', '2305779629', '2802154653');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('23', '14583', '2017-10-02 00:00:00', '2017-11-16 00:00:00', 'Αποθηκευτικού από κειμένων τρόπο σαν. Εφαρμογή σαν ανώδυνη γνωστή δε τεκμηριώνει. Ορίστε πάντως με τι τον. Αποδείξεις τι γραφικά σε παράδειγμα.', 'Αποκλειστικούς κόψεις κόψεις άρα μας μας. Βρίσκονται ρωτήσει των.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('24', '2603413238', '1311258636');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('24', '122691', '1994-07-06 00:00:00', '1994-07-16 00:00:00', 'Πλέον ποια απαράδεκτη χρησιμοποιούσες περισσότερες προγραμματιστής παίρνει επί. Κειμένων δοκιμάσεις αποκλειστικούς διορθώσεις τον. Για διορθώσεις πάρα απίστευτα.', 'Σταματάς διακόψουμε εφαμοργής πως ανεπιθύμητη πιο. Αν δύο ευκολότερο πολύ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('25', '1103565690', '1510827352');
