INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('27', '0809859588', '1002124868');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('27', '123551', '1948-11-15 00:00:00', '1948-12-17 00:00:00', 'Δουλεύει σταματάς πως οι επιδιόρθωση πρώτης. Μέρος προσθέσει έλεγχος εργοστασίου δοκιμάσεις σημαντικό νέο εξοργιστικά.', 'Ίδιο έτσι θυμάμαι δεν. Διαφήμιση σκεφτείς απαράδεκτη ωραίο αποκλειστικούς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('28', '1508483596', '2209794240');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('28', '64893', '1957-12-24 00:00:00', '1958-02-12 00:00:00', 'Των ατόμου διαφήμιση μου διολισθήσεις ναι. Επιδιόρθωση πάρεις προσεκτικά πάρεις τη χαρακτηριστικό διορθώσεις διορθώσει.', 'Ήδη της το. Νέου αποφάσισε εικόνες ροή περισσότερες. Άρα διαχειριστής θέλεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('29', '2408979400', '2505160976');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('29', '52540', '1999-10-05 00:00:00', '1999-11-24 00:00:00', 'Μπουν λετπά μέσης. Νόμιζες αρέσει βρίσκονται μη από τα προσοχή έτσι. Αντιλήφθηκαν πάρα τοπικές τρόπο συγγραφής δούλευε ανεπιθύμητη.', 'Χάος πάντως εργασίας αρέσει από αναγκάζονται συγχρόνως.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('30', '1002939858', '0406829350');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('30', '34913', '1990-04-04 00:00:00', '1990-05-01 00:00:00', 'Περιμένουν ανταγωνιστής συγγραφείς της έλεγχος εφαρμογής. Σχεδιαστής ρωτήσει αν εδώ πεδία. Οι παραδοτέου διαφήμιση νιρβάνα υπηρεσία.', 'Στραβά ρωτάει επενδυτής κλπ μάλλον κόλπα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('31', '1308712910', '1510827352');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('31', '17628', '1984-07-10 00:00:00', '1984-07-26 00:00:00', 'Κάτι δημιουργείς είχαμε βαθμό συνηθίζουν.', 'Πες πάντως μιας εκτελείται μάθε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('32', '1004904318', '0905574543');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('32', '71049', '1981-09-15 00:00:00', '1981-10-22 00:00:00', 'Τρόποι λετπά έλεγχος απόλαυσε κόλπα. Αν δύο ιδιαίτερα. Προσθέσει αρέσει σε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('33', '2305779629', '1510827352');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('33', '154187', '2008-01-29 00:00:00', '2008-03-20 00:00:00', 'Μάλλον μια χάος με καλύτερο έρθει ίδιο. Γραμμές προσεκτικά διακοπή δοκιμάσεις.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('34', '0112913316', '2703076674');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('34', '156303', '1960-11-12 00:00:00', '1960-11-16 00:00:00', 'Για αφήσεις ερωτήσεις κώδικάς συγγραφείς παραγωγικής. Περιμένουν ας φράση ανά επιστρέφουν ήδη κύκλο.', 'Περίπου άρα μέχρι υπηρεσία τρόποι μην διαπιστώνεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('35', '0712589234', '0212777006');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('35', '147762', '2007-11-02 00:00:00', '2007-12-31 00:00:00', 'Που πετούν χαρακτηριστικών προσθέσει εργαζόμενων ανά. Και κάνεις σας τρέξει ήδη τις κάτι.', 'Σαν πλέον σε μηχανής εφαρμογή. Αυτός μέχρι μάλλον ακούσει έχω βαθμό.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('36', '0712546968', '1204835006');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('36', '127449', '1956-09-02 00:00:00', '1956-10-21 00:00:00', 'Στο μέσης μη ελέγχου τύπους περιβάλλοντος της. Εξακολουθεί ανακλύψεις διαδίκτυο τους μου.', 'Έστελνε υψηλότερη μας δε. Ως όταν ναι μπορούσες. Περιεχόμενα σε μαγικά πάρεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('37', '2108408566', '2005204831');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('37', '74239', '1989-01-30 00:00:00', '1989-02-13 00:00:00', 'Αγοράζοντας γέλασαν ένα βασανίζουν πάντα με. Όχι στραβά μπορούσες περιβάλλοντος συνεντεύξεις.
