INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('39', '2601400380', '1706515549');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('39', '30763', '2018-09-14 00:00:00', '2018-09-25 00:00:00', 'Λέει αλγόριθμου βάζοντας. Στραβά ροή συνηθίζουν μέχρι διάβασε γραμμής από στήλες.', 'Ανά αν μερικούς έχω στέλνοντάς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('40', '1103565690', '0412254286');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('40', '82143', '2025-03-13 00:00:00', '2025-04-15 00:00:00', 'Το αποστηθίσει ανεπιθύμητη χρόνου. Δεν ορίστε εφαμοργής εγώ χρησιμοποιούνταν οι. Προγραμματιστής δε πλέον δούλευε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('41', '1709483162', '2408728749');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('41', '154299', '2013-11-23 00:00:00', '2013-11-29 00:00:00', 'Εντολές πηγαίου κειμένων δημιουργια αν. Επιδιορθώσεις συγκεντρωμένοι σημαντικός γεύματος ήδη παίρνουν νιρβάνα. Λοιπόν βάζοντας πλέον δοκιμάσεις.', 'Τύπου αυτός του μπορούσες καλύτερο γέλασαν πάρα. Τέλειοι έτσι νέο κι ας θα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('42', '1905434261', '2105933683');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('42', '73394', '2004-08-06 00:00:00', '2004-09-02 00:00:00', 'Έλεγχος χρησιμοποίησέ ο δεν έχω δε άλγεβρα στραβά. Προσεκτικά επεξεργασία καταλάθος διοικητικό ανά πάντως απίστευτα. Πιο κανόνα στη τους όχι.', 'Του προσεκτικά εικόνες τι νέου. Συγγραφής εργάστηκε νιρβάνα γέλασαν βουτήξουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('43', '1810717683', '2611435276');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('43', '75633', '2007-12-20 00:00:00', '2008-01-02 00:00:00', 'Άτομο πρώτο διοικητικό εγώ. Απομόνωση σε εδώ δε μαγικά με.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('44', '1103565690', '3004907878');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('44', '99385', '2017-11-02 00:00:00', '2017-12-12 00:00:00', 'Ως διευθυντές έστελνε ποια. Διαδίκτυο επιχείριση προκαλείς επιδιόρθωση εργάστηκε δυστυχώς να. Κώδικα εκθέσεις μου ότι.', 'Περιμένουν ειδικά να διολισθήσεις αντιλήφθηκαν εγώ. Και επιχείριση πάντα όταν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('45', '2108408566', '2408728749');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('45', '131161', '2015-07-04 00:00:00', '2015-07-21 00:00:00', 'Τον πλέον χρειάζονται πιο στέλνοντάς είχαμε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('46', '0810679721', '0602405324');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('46', '139944', '2026-09-18 00:00:00', '2026-09-20 00:00:00', 'Τρέξει έχω σταματάς. Σημαντικός πετούν συγχωνευτεί ποσοστό υποψήφιο ορίστε μεταγλωτιστής.', 'Έξι μπορούσες τελειώσει βιαστικά βασανίζουν δοκιμάσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('47', '2811724151', '0110225992');
