INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('48', '1701486274', '2607682771');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('48', '56948', '1959-09-09 00:00:00', '1959-09-17 00:00:00', 'Κι εφαρμογή πάντα αλγόριθμου την. Έστελνε χαρακτηριστικό ειδικά διασφαλίζεται κι.', 'Πρώτο χαρακτηριστικό μέχρι για γνωρίζουμε καταλάθος περιβάλλον.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('49', '0809857914', '2303550343');
