INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('50', '1504919832', '2708575377');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('50', '12790', '1954-10-23 00:00:00', '1954-11-05 00:00:00', 'Κανείς εσωτερικών έλεγχος γέλασαν. Ζητήσεις πλέον αθόρυβες μεταφραστής.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('51', '2312884240', '2104830350');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('51', '142947', '1955-08-10 00:00:00', '1955-09-02 00:00:00', 'Διάσημα μας τύπους ευκολότερο φαινόμενο. Ιδιαίτερα δε τον περιβάλλοντος χειρότερα. Διάβασε τη εκτελέσεις αφήσεις.', 'Βγήκε πως πολύ κάνε αναγκάζονται της. Κανένας ζητήσεις ημέρα την.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('52', '2811724151', '0706422141');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('52', '7216', '1955-10-17 00:00:00', '1955-11-16 00:00:00', 'Αναφέρονται ποια γραμμή νιρβάνα προκαλείς τον. Όταν νιρβάνα επιδιόρθωση ύψος. Διαφήμιση κλπ μερικούς αυτός δύο επί που.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('53', '2907939803', '2303551551');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('53', '57115', '1950-05-31 00:00:00', '1950-07-20 00:00:00', 'Συγχρόνως δύο των ποια προϊόντα ιδιαίτερα πηγαίου χώρου. Δε εξαρτάται εκτός αποστηθίσει πεδία να. Ναι συνηθίζουν συγχωνευτεί γνωρίζουμε μην φράση ποια.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('54', '0702453133', '0104835316');
