INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('56', '2207829834', '2812487982');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('56', '11283', '1957-08-16 00:00:00', '1957-10-12 00:00:00', 'Ο διακόψουμε κι χαρακτηριστικών. Δε ανεπιθύμητη προσθέσει μάτσο αν ως νέων.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('57', '1103857156', '0308427033');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('57', '150089', '2014-08-01 00:00:00', '2014-08-13 00:00:00', 'Δείξει δουλεύει ποια πάρεις προσθέσει. Επεξεργασία παραγωγικής διολισθήσεις εργασίας. Ανά απόλαυσε το επί ίδιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('58', '0712546968', '0410092692');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('58', '131381', '1973-09-07 00:00:00', '1973-10-26 00:00:00', 'Διορθώσει ως αναγκάζονται. Χρησιμοποιώντας παράδειγμα καλύτερο δοκιμάσεις ρωτήσει.', 'Νέου ελέγχου λέει έστελνε ύψος. Εδώ από μου απαραίτητο σημεία.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('59', '1502405362', '1406880489');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('59', '62379', '1969-04-10 00:00:00', '1969-04-15 00:00:00', 'Χρησιμοποιούνταν πάντα μας μπορούσες εκδόσεις μαγικά σίγουρος. Αποστηθίσει γέλασαν καταλάθος χαμηλός για βάζοντας ας. Παραδοτέου από περιεχόμενα χρονοδιαγράμματα πρώτοι εκτός πως και.', 'Ένας όταν υποψήφιο κάτι. Τη λες γραμμή επιχείριση πεδία ατόμου επεξεργασία.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('60', '1502405362', '0411099817');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('60', '47934', '1951-02-10 00:00:00', '1951-03-23 00:00:00', 'Το μας μάλλον. Προσπαθούν μην ποια εργασίας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('61', '2312469220', '2303551551');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('61', '88242', '1951-05-25 00:00:00', '1951-07-19 00:00:00', 'Στις ο πρόσληψη γνωρίζουμε γεγονός παραγωγικής ήδη γιαυτό. Πλέον πιο όταν διαφήμιση χαρακτηριστικό παίξουν επί. Διορθώσει έτσι και συγγραφείς μέχρι ζητήσεις θέμα για.', 'Μου στα νέου που αποδείξεις έξι. Από από πλέον σπίτι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('62', '2012950130', '2105171626');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('62', '100684', '1963-11-28 00:00:00', '1963-12-25 00:00:00', 'Μα είχαμε γιαυτό την τύπους. Ένας σας δεν νέα έχω. Έχω διακοπής άρα εκτελέσεις λαμβάνουν αλγόριθμου. Πόρτες την όσο προκύπτουν για κάνεις εξαρτάται φακέλους.', 'Χρησιμοποιούνταν έτσι πλέον για καλύτερο σημαντικό.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('63', '2312590646', '2709864379');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('63', '74238', '1999-12-23 00:00:00', '2000-01-08 00:00:00', 'Εταιρείες εξακολουθεί ιδιαίτερα εφαρμογής σωστά καλύτερο. Νέων περισσότερες εταιρείες συνεντεύξεις και διακοπή αρχεία. Μέχρι επί θέλεις μου οι.', 'Τεκμηριώνει δημιουργια μετράει ένα. Στη αν δείξει πάντως.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('64', '1510499016', '0709200165');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('64', '127481', '1987-05-20 00:00:00', '1987-06-12 00:00:00', 'Μετρήσεις κάτι μέχρι δύο. Δε δυστυχής αφήσεις φακέλους.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('65', '2902566054', '2709864379');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('65', '47680', '1945-06-14 00:00:00', '1945-06-23 00:00:00', 'Θα ίδιο αναφορά προσλάμβανες ίδιο παίρνουν σε. Αφήσεις δύο βρίσκονται εξοργιστικά κόψεις μη παράδειγμα.', 'Ανά ως δημιουργια απόλαυσε αγοράζοντας δημιουργια προκαλείς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('66', '1510499016', '1203945952');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('66', '91074', '1964-06-23 00:00:00', '1964-07-18 00:00:00', 'Συνεχώς για τρόπο έγραψες μεταφραστής πακέτων. Ζητήσεις διαπιστώνεις κανόνα διασφαλίζεται. Υπηρεσία ευκολότερο σου δυστυχώς περίπου δε νέα.', 'Μπουν εσωτερικών βουτήξουν πάντα επιχείριση στα μα. Περισσότερη που σε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('67', '2609467791', '0508507552');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('67', '25935', '1944-01-10 00:00:00', '1944-02-02 00:00:00', 'Συνάδελφος σε χρησιμοποιούσες πάρεις. Μου τρέξει εργάστηκε ρουτίνα επενδυτής. Εργαζόμενων απαρατήρητο πηγαίου.', 'Στο δεν σχεδιαστής μερικούς. Αναγκάζονται ειδικά χρησιμοποιούσες δοκιμάσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('68', '1310995579', '1703064879');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('68', '94706', '1968-04-15 00:00:00', '1968-06-02 00:00:00', 'Χάος δε εκδόσεις με αθόρυβες. Το χώρου ανά κρατάει. Συγγραφής των όταν νέο κόψεις εκείνου σωστά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('69', '2312469220', '2207247744');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('69', '102386', '1965-06-13 00:00:00', '1965-07-05 00:00:00', 'Προσθέσει ανεπιθύμητη επιδιορθώσεις ας ανά. Περιμένουν περισσότερες πολύ λοιπόν τελειώσει όσο μην. Ανταγωνιστής τα περιεχόμενα του. Ανακλύψεις μέχρι σου ερώτηση ποια απαρατήρητο πάντα.', 'Εδώ προσλάμβανες ότι σημεία για διολισθήσεις. Τρόπο βάζοντας έστειλε ρωτήσει.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('70', '1004904318', '2503675576');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('70', '69116', '1955-05-19 00:00:00', '1955-05-23 00:00:00', 'Μεταφραστής λαμβάνουν στις έξι. Όταν αποφάσισε χάος άρα εξοργιστικά έτσι τρόπο.', 'Λετπά τελειώσει παραδώσεις τεσσαρών έχω. Όταν τι προσοχή εσωτερικών κι το τους.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('71', '0803481218', '1510001508');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('71', '84764', '2007-06-21 00:00:00', '2007-06-25 00:00:00', 'Ζητήσεις όσο σε δύο έτοιμος τα. Προσεκτικά ρωτάει δημιουργείς πάντως μου.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('72', '1905434261', '2105933683');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('72', '47873', '1961-07-18 00:00:00', '1961-07-21 00:00:00', 'Μέρος βασανίζουν προβληματική τεκμηριώνει. Αρέσει της κύκλο επί στις περισσότερη. Πάντα γραφικά ημέρα έξι βιαστικά.', 'Θυμάμαι αν καλύτερο θυμάμαι περισσότερες νέα εκδόσεις συνεντεύξεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('73', '2601400380', '2104830350');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('73', '82006', '1964-04-05 00:00:00', '1964-04-26 00:00:00', 'Έστειλε δουλεύει κάτι διορθώσει μου προγραμματιστής διορθώσεις. Τον μεταφραστής τον.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('74', '1403988053', '1001210095');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('74', '16496', '1965-07-18 00:00:00', '1965-08-02 00:00:00', 'Δωροδοκηθούν φράση λίγο πολύ παραδοτέου. Χειρότερα κρατάει έστειλε έστειλε.', 'Εκτός εκτός αυτήν έχω του για θα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('75', '2108408566', '1203945952');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('75', '96398', '1984-01-03 00:00:00', '1984-01-14 00:00:00', 'Ωραίο μια παραδώσεις άπειρα δεν έχω χαρακτηριστικό εξοργιστικά. Δυστυχώς είχαμε δεν τον μηχανής σας κανόνα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('76', '0605885194', '0204677057');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('76', '19416', '2012-06-19 00:00:00', '2012-08-09 00:00:00', 'Τοπικές ανακλύψεις ποσοστό εργάστηκε χρονοδιαγράμματα περιεχόμενα ήδη. Ίδιο τεκμηριώνει για λέει. Απαράδεκτη σημεία πες απαρατήρητο ρωτήσει ίδιο λες.', 'Λαμβάνουν νέου μάλλον. Ανώδυνη φαινόμενο που γραμμές ελέγχου έτσι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('77', '2711746424', '1406880489');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('77', '89521', '2003-09-24 00:00:00', '2003-11-13 00:00:00', 'Τύπους ποσοστό ανά διευθυντές δε. Κρατάει σημεία πολύ μιας στις του στα αθόρυβες. Εκτός χαρτιού μας θέματα επιστρέφουν σου δωροδοκηθούν ώρα.', 'Συνηθίζουν μην μέγιστη χαρτιού άλγεβρα. Ως πλέον δίνοντας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('78', '1504919832', '1303031388');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('78', '153117', '2020-05-31 00:00:00', '2020-07-27 00:00:00', 'Παίρνουν πάντως ήδη ίδιο αναφορά πως επί. Ανά παράδειγμα όχι φράση πάντα ατόμου στη κάνεις. Δημιουργείς κύκλο κλπ επί εντολές εδώ. Ώρα άλγεβρα καλύτερο θα ροή.', 'Κρατήσουν χρησιμοποιούσες μηχανής χρησιμοποιώντας εσωτερικών.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('79', '1703007463', '1610679676');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('79', '101974', '1943-07-28 00:00:00', '1943-08-01 00:00:00', 'Ένας πρόσληψη μερικούς εργάστηκε.', 'Ακούσει στις πως τοπικές ως μηχανής. Γιαυτό ερωτήσεις ποια στη διαχειριστής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('80', '2207829834', '2603474333');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('80', '117525', '2008-03-14 00:00:00', '2008-04-21 00:00:00', 'Προσπαθήσεις διακοπής σημαντικό ερωτήσεις σαν στο φακέλους. Τρόπο εταιρείες πάρεις χρειάζονται δοκιμάσεις πως. Εκείνου διοικητικό τις βγήκε.', 'Επεξεργασία των αν χαρτιού τρόπο λοιπόν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('81', '0111535131', '1510001508');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('81', '21107', '2022-05-06 00:00:00', '2022-05-11 00:00:00', 'Εκείνου εξακολουθεί εδώ. Ως θέλεις ίδιο στις με την.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('82', '1310995579', '1909645137');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('82', '126664', '1961-09-15 00:00:00', '1961-10-19 00:00:00', 'Στήλες ας σε μερικούς αυτός. Μηχανής ατόμου χρονοδιαγράμματος όσο διακοπής ανταγωνιστής πηγαίου. Μα παραγωγικής ρουτίνα στις ακούσει.', 'Ως λετπά πιο ήδη σταματάς μέχρι χειρότερα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('83', '1709483162', '1005683509');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('83', '51752', '2010-03-15 00:00:00', '2010-04-02 00:00:00', 'Συνηθίζουν διακοπή μου μας ερώτηση σκεφτείς ερώτηση. Εντολές περιβάλλον χρησιμοποιούνταν φακέλους. Τεκμηριώνει ανταγωνιστής γνωρίζουμε περιεχόμενα εξαρτάται.', 'Δε ανώδυνη σημαντικός εφαμοργής και των διάσημα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('84', '1502405362', '1005683509');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('84', '67890', '1989-03-26 00:00:00', '1989-04-11 00:00:00', 'Πρώτοι ελέγχου περισσότερη τα. Που που εκδόσεις διαδίκτυο ελέγχου πάρα. Δούλευε έξι κώδικα πιο διορθώσει έστειλε.', 'Προγραμματιστές μέχρι μια μου εκτελέσει. Δύο εγώ ως.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('85', '2207829834', '2303550343');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('85', '67444', '1974-09-25 00:00:00', '1974-10-03 00:00:00', 'Στη δοκιμάσεις τρόπο προσθέσει. Ώρα στα προσθέσει μιας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('86', '0809857914', '1305697404');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('86', '102549', '1974-04-06 00:00:00', '1974-05-07 00:00:00', 'Φράση σκεφτείς είχαμε νέα έξι περισσότερες χρειάζονται πάντα. Μας αθόρυβες ώρα στραβά τη περίπου.', 'Των μας εγώ συνεχώς. Πάντα θα ποσοστό. Με κι ώρα μπουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('87', '2510514026', '1106137666');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('87', '111816', '1989-09-10 00:00:00', '1989-10-16 00:00:00', 'Μου τα έξι εδώ με λίγο εξοργιστικά. Εκτός εξακολουθεί θα εφαρμογή σε. Αναφέρονται καταλάθος απίστευτα αν γνωρίζουμε που. Μαγικά σε μια τύπου προβληματική.', 'Χρησιμοποιούνταν αντιλήφθηκαν σημαντικό. Επιδιόρθωση εσωτερικών άλγεβρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('88', '1210434994', '0411099817');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('88', '78398', '1954-06-09 00:00:00', '1954-06-16 00:00:00', 'Όσο εκθέσεις επιχείριση τους σας κι. Έστελνε κανείς γραφικά προσοχή χρησιμοποιώντας για εικόνες.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('89', '1001684330', '0406829350');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('89', '118906', '1982-11-27 00:00:00', '1983-01-01 00:00:00', 'Για επί σωστά ανώδυνη. Κλπ νέου ωραίο έξι δωροδοκηθούν ανακλύψεις ναι. Ρωτήσει βιαστικά ποια τα ένα όσο μερικούς. Οι ίδιο δεν σταματάς τι προκύπτουν εργαζόμενων.', 'Χρονοδιαγράμματος στραβά επιδιορθώσεις σπίτι πολύ απαρατήρητο. Θα δύο εργασίας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('90', '1103565690', '0705111952');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('90', '28107', '2002-04-10 00:00:00', '2002-05-31 00:00:00', 'Απαράδεκτη πετούν ελέγχου πήρε. Των έτοιμος διασφαλίζεται αλγόριθμου αυτήν διορθώσει χρονοδιαγράμματα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('91', '0502786206', '3004907878');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('91', '88115', '1941-12-09 00:00:00', '1942-02-02 00:00:00', 'Υψηλότερη ποσοστό βιβλίο μπουν από διορθώσει. Αποκλειστικούς του απαραίτητο πετάνε έτσι περιβάλλοντος δεν κλπ. Εργαζόμενοι άπειρα μου το. Σαν σε εγώ αγοράζοντας δυστυχής αποκλειστικούς.', 'Πιο τρόπο ορίστε απίστευτα. Ανεπιθύμητη υψηλότερη πετάξαμε ερώτηση μας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('92', '1701486274', '1210561667');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('92', '4346', '2013-03-29 00:00:00', '2013-05-03 00:00:00', 'Να δούλευε τοπικές τι. Εφαμοργής αποκλειστικούς ιδιαίτερα γραμμής πάρεις νιρβάνα διάσημα υποψήφιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('93', '2710708126', '2603474333');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('93', '40614', '2012-02-22 00:00:00', '2012-03-21 00:00:00', 'Πόρτες παράδειγμα υπηρεσία χρειάζονται επί κρατήσουν στα. Λοιπόν ημέρα πηγαίου ανεπιθύμητη νόμιζες.', 'Συγχωνευτεί προσλάμβανες χρονοδιαγράμματος δύο ήδη. Γραφικά σκεφτείς εργασίας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('94', '2403634296', '1708511999');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('94', '24384', '2009-11-18 00:00:00', '2009-12-14 00:00:00', 'Φαινόμενο ήδη που πες γέλασαν τέλειοι άπειρα τύπου. Επί διακοπή διαχειριστής λοιπόν σταματάς εκτός έτσι διακοπή.', 'Συγχρόνως βιβλίο ώρα επί λέει χρειάζονται με. Διάσημα αποστηθίσει των.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('95', '2312469220', '3009111588');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('95', '54424', '1945-07-30 00:00:00', '1945-08-28 00:00:00', 'Τον παραδώσεις δουλεύει τις δίνοντας. Χρόνου χρησιμοποιώντας σχεδιαστής ανακλύψεις άπειρα ποια. Τον βουτήξουν τρέξει γειτονιάς.', 'Πάντα επιχείριση θα τύπου νέων. Δεν συνεχώς δημιουργήσεις με παίρνουν κάτι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('96', '2312590646', '1204835006');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('96', '37830', '1945-03-03 00:00:00', '1945-04-08 00:00:00', 'Κι σημεία προσοχή μάθε προγραμματιστές ως μη συνεχώς. Παίξουν χαρτιού εκείνου πιο μηχανής γραμμή. Κι διολισθήσεις μηχανής δυστυχής δημιουργήσεις αθόρυβες ήδη λες.', 'Τα αναφορά τον από επιδιορθώσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('97', '0809857914', '0110225992');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('97', '62450', '1978-12-12 00:00:00', '1979-01-11 00:00:00', 'Στήλες δουλεύει έλεγχος ερωτήσεις σε σου. Των κανόνα μάτσο απομόνωση χρησιμοποιούνταν πετάξαμε πάντως. Του δωροδοκηθούν πήρε απαράδεκτη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('98', '0712589234', '0402706196');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('98', '66978', '1994-03-11 00:00:00', '1994-03-30 00:00:00', 'Επιχείριση προσοχή άλγεβρα μου ως πολύ κόψεις εδώ. Διακόψουμε έξι χαρακτηριστικών εργάστηκε αρπάζεις εγώ νιρβάνα.', 'Ναι συνεντεύξεις περιμένουν ίδιο μέσης σημεία.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('99', '0712589234', '2711937465');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('99', '35841', '1974-11-23 00:00:00', '1974-11-29 00:00:00', 'Πάντως δε περιεχόμενα δύο συνηθίζουν έξι περιβάλλοντος. Ζητήσεις ευκολότερο ήδη κι δύο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('100', '1508483596', '0512717602');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('100', '72900', '1972-02-16 00:00:00', '1972-02-24 00:00:00', 'Σας ποια περιμένουν επενδυτής. Εργοστασίου μέσης αποκλειστικούς αναφορά εκθέσεις.', 'Εκτός δε συνεντεύξεις νέα χαμηλός εφαρμογή.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('101', '1509007909', '1308127659');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('101', '161037', '1954-12-25 00:00:00', '1955-01-13 00:00:00', 'Διαδίκτυο φακέλους εκτελείται διακόψουμε έστειλε απαραίτητο. Της λίγο πάντα φαινόμενο επί στις. Και δύο μεταγλωτιστής μα ταξινομεί ας.', 'Κι μια γέλασαν πάρα προκαλείς μεταφραστής μετρήσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('102', '2101441639', '2802154653');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '39173', '1952-09-26 00:00:00', '1952-11-06 00:00:00', 'Δύο μέγιστη δε προσλάμβανες αποστηθίσει νιρβάνα. Εκτός διαχειριστής γραφικά αναφέρονται συνάδελφος αυτός αυτήν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('103', '0706562391', '0705111952');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '113755', '1974-01-07 00:00:00', '1974-02-27 00:00:00', 'Κάτι επί αρπάζεις άτομο διαχειριστής εξακολουθεί. Βρίσκονται ήδη στο όχι εφαρμογή μηχανής ανά γνωρίζουμε. Θέμα έλεγχος δυστυχώς εικόνες δεν άρα. Επιστρέφουν διακοπής σας αναγκάζονται.', 'Εντολές παράγοντες από μη απόλαυσε κώδικα γραμμή.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('104', '1509007909', '0105497460');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('104', '91574', '2020-05-08 00:00:00', '2020-06-06 00:00:00', 'Και έξι χρησιμοποιούνταν ναι χρησιμοποιούνταν πόρτες. Όχι βάζοντας ανακλύψεις περισσότερη πάντως απίστευτα.', 'Μην ένα περιεχόμενα γεύματος ελέγχου ανακλύψεις επί χρησιμοποιώντας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('105', '1803580830', '1404027826');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('105', '83149', '1953-05-27 00:00:00', '1953-07-14 00:00:00', 'Τον πάντως γνωστή μη πως. Συγκεντρωμένοι πήρε βρίσκονται μηχανής.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('106', '3005652478', '0105497460');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('106', '24242', '1942-10-19 00:00:00', '1942-10-29 00:00:00', 'Κάτι θέμα φακέλους μην δούλευε μου. Βιβλίο σημαντικός σαν παράδειγμα εγώ. Πηγαίου να τους εκτός υπηρεσία δύο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('107', '2311684983', '2401076081');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('107', '118515', '2004-07-02 00:00:00', '2004-08-12 00:00:00', 'Σε μην στις χαμηλός θα βασανίζουν. Νιρβάνα διακοπής μιας. Πάρα σχεδιαστής έξι παράδειγμα πρόσληψη ένα.', 'Βαθμό τι θα πρώτοι. Εφαρμογή μην σε φακέλους παραπάνω.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('108', '1510499016', '0702868131');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('108', '68388', '1948-08-15 00:00:00', '1948-09-05 00:00:00', 'Κώδικάς περιμένουν πολύ πιο άτομο γειτονιάς κώδικα. Προβληματική καταλάθος τους μέγιστη κι μια.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('109', '2305779629', '2707592034');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('109', '136621', '1952-07-11 00:00:00', '1952-08-15 00:00:00', 'Διορθώσει ανακλύψεις από φράση ιδιαίτερα. Ποια προσοχή κοιτάζοντας μπορούσες. Λαμβάνουν ρωτήσει να πάρα.', 'Και επιδιορθώσεις απίστευτα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('110', '2312884240', '0403473442');
