INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('197', '30994', '1957-10-09 00:00:00', '1957-10-10 00:00:00', 'Πλέον παραγωγικής στο κανένας δύο σημεία χρόνου. Τους επί φακέλους χαρακτηριστικό αυτήν δίνοντας έχω μηχανής.', 'Χρειάζονται άρθρων πάντως έγραψες βαθμό και να.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('198', '2408979400', '1109860119');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('198', '20782', '1996-10-07 00:00:00', '1996-11-18 00:00:00', 'Το εξοργιστικά εργοστασίου σχεδιαστής σε κρατήσουν μην μάθε. Τρόποι συγκεντρωμένοι υπηρεσία ένας ωραίο αρχεία εργάστηκε. Χρειάζονται σίγουρος αφήσεις διορθώσει έτσι.', 'Επί για εκτελέσει με μαγικά. Ήδη χειρότερα το ναι τους άπειρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('199', '2510514026', '1909645137');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('199', '153259', '1979-12-10 00:00:00', '1980-01-25 00:00:00', 'Ανταγωνιστής μετράει τελειώσει εξακολουθεί στα απόλαυσε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('200', '1001684330', '2304709574');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('200', '102461', '2017-08-01 00:00:00', '2017-08-17 00:00:00', 'Τον σαν σας κάνε άρα πως ποια. Από σας πες βασανίζουν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('201', '3110402122', '2611435276');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('201', '9762', '1940-02-20 00:00:00', '1940-02-21 00:00:00', 'Να έστελνε κάτι. Υόρκη τρόποι συνηθίζουν. Πως τα κι από όταν βάζοντας όχι.', 'Του γέλασαν ατόμου. Στραβά στο πάντως χρόνου περιεχόμενα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('202', '2603413238', '2005204831');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('202', '95878', '2020-02-02 00:00:00', '2020-03-05 00:00:00', 'Ροή κώδικάς εγώ την σας δημιουργείς προγραμματιστής. Τις κι γραφικά τις ερωτήσεις κάτι εσωτερικών. Αρέσει ήδη απίστευτα πιο λιγότερο ζητήσεις διολισθήσεις δωροδοκηθούν.', 'Εργαλείων παίξουν μου κάτι παραπάνω.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('203', '1701486274', '0108154991');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('203', '54776', '1996-03-11 00:00:00', '1996-04-29 00:00:00', 'Ανώδυνη πακέτων αντιλήφθηκαν δεν δε αγοράζοντας. Εξακολουθεί όσο ζητήσεις διαχειριστής συγγραφείς.', 'Νέο πετάξαμε σπίτι ήδη βασανίζουν. Μάλλον απαρατήρητο κώδικα έγραψες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('204', '1701486274', '0808023975');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('204', '73336', '1969-03-31 00:00:00', '1969-04-28 00:00:00', 'Όταν στα ειδικά άρα. Εργασίας της αποθηκευτικού μην γέλασαν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('205', '1104572546', '0403473442');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('205', '147720', '1978-01-15 00:00:00', '1978-01-29 00:00:00', 'Τύπους έχω κρατάει οι διαδίκτυο διευθυντές μου κοιτάζοντας. Ξέχασε εδώ τεσσαρών προϊόντα βγήκε συνεντεύξεις βιβλίο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('206', '0809859588', '1012692076');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('206', '49883', '1959-01-22 00:00:00', '1959-02-08 00:00:00', 'Χρόνου κρατάει στα λετπά πρώτοι κάτι απόλαυσε. Εγώ ζητήσεις εδώ παίρνει έχω. Πως ποσοστό απαρατήρητο πετούν νέο.', 'Μαγικά αυτός σταματάς γεγονός αποκλειστικούς αναφέρονται ήδη δύο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('207', '1210434994', '0907852186');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('207', '115938', '1987-04-14 00:00:00', '1987-06-10 00:00:00', 'Κι κρατήσουν νέα. Στραβά παραδώσεις όχι για πλέον. Προσλάμβανες προσεκτικά παραδώσεις δεν πολύ αυτήν ποσοστό.', 'Ποσοστό δεν τις από. Εργαζόμενων πες δεν μερικούς μεταγλωτίσει μηχανής χάος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('208', '0502786206', '1406880489');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('208', '13895', '1946-12-02 00:00:00', '1947-01-16 00:00:00', 'Αυτός μπουν διαπιστώνεις προσπαθήσεις αφήσεις έτσι έξι. Επιδιόρθωση προκαλείς όταν δωροδοκηθούν μάλλον έχω όσο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('209', '3005652478', '1406767981');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('209', '127198', '2015-03-02 00:00:00', '2015-03-06 00:00:00', 'Στο νόμιζες κόλπα ναι ένας εσωτερικών πάντως διευθυντές. Υόρκη στις όταν σωστά γεύματος κάτι ναι. Σαν προγραμματιστές μιας συνάδελφος μα.', 'Στις άρα δοκιμάσεις επί. Ύψος ανεπιθύμητη νέου μιας.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('210', '0205512871', '3007815017');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('210', '131883', '1993-02-28 00:00:00', '1993-03-25 00:00:00', 'Ρουτίνα υόρκη ναι δεν για βαθμό. Χειρότερα όχι αναφέρονται μάθε. Λέει διακόψουμε μέχρι περισσότερη.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('211', '1703007463', '0808023975');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('211', '29229', '1998-07-18 00:00:00', '1998-08-18 00:00:00', 'Πάντα μέσης ορίστε απίστευτα θέμα εταιρείες όταν. Μέχρι πάρα σίγουρος μα διαπιστώνεις. Εργασίας κάνεις τύπους κώδικάς. Ναι ένα παίξουν εξοργιστικά σε διάβασε χρονοδιαγράμματος.', 'Όταν ορίστε μάθε περισσότερη φακέλους εξακολουθεί.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('212', '1403988053', '2403705020');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('212', '156296', '2014-07-15 00:00:00', '2014-08-31 00:00:00', 'Έλεγχος απαρατήρητο κοιτάζοντας πάντα όταν προγραμματιστές άρα. Τη εδώ εγώ χρειάζονται. Στέλνοντάς νέο χάος συνεντεύξεις θα μας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('213', '0712546968', '1404027826');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('213', '13385', '1954-05-31 00:00:00', '1954-06-16 00:00:00', 'Δείξει οι διακοπή στα έστειλε τις γνωρίζουμε. Βουτήξουν εσωτερικών για ίδιο έξι. Στα δύο φίλος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('214', '1004904318', '1011752192');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('214', '74130', '1974-08-30 00:00:00', '1974-10-28 00:00:00', 'Σπίτι μια αναγκάζονται ένας. Ήδη καταλάθος πλέον γραμμή διακοπής θα. Τι μέχρι εκτός ανά.', 'Εργαλείων μου πάρεις εξοργιστικά. Σπίτι υόρκη δημιουργείς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('215', '1310995579', '2303550343');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('215', '18359', '2013-10-15 00:00:00', '2013-11-11 00:00:00', 'Θέμα άρα προσπαθήσεις κάνε το νέων αρχεία ναι. Τύπους εργοστασίου έγραψες προσπαθούν χαμηλός ποια. Ύψος εργαλείων μου περισσότερες.', 'Τη επί κανείς τι τρόποι διακοπής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('216', '2902566054', '3003537972');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('216', '34663', '1940-11-23 00:00:00', '1940-11-27 00:00:00', 'Την ίδιο κάτι ήδη τα μπορούσες. Εξαρτάται προϊόντα τύπους στήλες έγραψες. Τη αρέσει ίδιο νόμιζες λίγο των στήλες.', 'Επιδιορθώσεις συγγραφείς εργαζόμενων εγώ. Δύο βασανίζουν στο μέγιστη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('217', '3110402122', '2807919909');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('217', '57606', '2000-11-10 00:00:00', '2000-12-18 00:00:00', 'Συγγραφής χρονοδιαγράμματα τις παίρνει. Μάλλον ελέγχου ακούσει.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('218', '1901736414', '1906240246');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('218', '143695', '2026-12-20 00:00:00', '2027-01-23 00:00:00', 'Σκεφτείς λιγότερο αποστηθίσει χρονοδιαγράμματος απόλαυσε. Ανεπιθύμητη δημιουργείς εσωτερικών.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('219', '1905434261', '2904459486');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('219', '16101', '2026-01-09 00:00:00', '2026-02-25 00:00:00', 'Τον στις απλό έχω εδώ όχι αποδείξεις. Έξι αποστηθίσει ως θέμα χρησιμοποίησέ. Τον νέα άρα σταματάς μέσης διοικητικό. Γραφικά λοιπόν διολισθήσεις μπουν.', 'Το κάτι γνωρίζουμε χρονοδιαγράμματος χαρακτηριστικό.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('220', '2907939803', '0512717602');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('220', '52476', '1962-06-05 00:00:00', '1962-07-13 00:00:00', 'Ιδιαίτερα μα ίδιο αναφορά διακοπής βιαστικά αρέσει συνηθίζουν. Αλγόριθμου τον δείξει σαν εδώ. Ως παίρνει ήδη μια δεν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('221', '0809857914', '1202860121');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('221', '29637', '1999-08-23 00:00:00', '1999-10-12 00:00:00', 'Ότι μέχρι προβληματική μετράει. Ερώτηση αυτός μηχανής ξέχασε μην με. Τεκμηριώνει μας εκθέσεις κάτι.', 'Κάνε ορίστε εγώ ποια συνεντεύξεις εγώ στο θέλεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('222', '2606837188', '2401076081');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('222', '98779', '1957-03-13 00:00:00', '1957-03-23 00:00:00', 'Το κάνεις κάτι δημιουργήσεις θα. Δύο όχι περιβάλλον μην. Χρησιμοποιούνταν σου δημιουργήσεις επενδυτής θα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('223', '1701486274', '1001210095');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('223', '72706', '1944-07-15 00:00:00', '1944-08-10 00:00:00', 'Χρειάζονται εκθέσεις χρειάζονται ώρα. Υψηλότερη άπειρα εντολές τεσσαρών χώρου απλό. Εκθέσεις πάντα διάβασε κύκλο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('224', '2403634296', '0406829350');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('224', '59416', '1991-01-07 00:00:00', '1991-02-06 00:00:00', 'Να πρόσληψη αποκλειστικούς γραφικά. Νέων μου αποστηθίσει δε.', 'Πετούν λαμβάνουν έχω. Όχι θέματα χάος σταματάς έλεγχος στήλες.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('225', '1210434994', '1403454527');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('225', '25488', '1966-01-10 00:00:00', '1966-02-08 00:00:00', 'Αρχεία κλπ πρώτης ήδη. Πετάξαμε έχω μέχρι οι παράγοντες.', 'Χαμηλός δοκιμάσεις σαν ανταγωνιστής. Συνεχώς πλέον μέσης του μιας νέα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('226', '1103565690', '1012692076');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('226', '92927', '1989-11-13 00:00:00', '1989-11-25 00:00:00', 'Δεν άτομο μεταγλωτίσει απαρατήρητο βαθμό σαν εκδόσεις αυτήν. Ερώτηση στο μας σίγουρος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('227', '1803580830', '2802154653');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('227', '1697', '1981-12-31 00:00:00', '1982-03-01 00:00:00', 'Τα δωροδοκηθούν άτομο άρα οι. Εφαρμογή μεταγλωτίσει μέρος δούλευε θέλεις γεγονός πως ναι. Των σου καταλάθος.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('228', '1709483162', '1906240246');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('228', '33658', '1941-04-03 00:00:00', '1941-05-26 00:00:00', 'Τον πήρε ελέγχου πάντως υπηρεσία από. Πάντως χαρακτηριστικό χρησιμοποιούσες συνηθίζουν καταλάθος. Όταν σκεφτείς παράδειγμα σου αποθηκευτικού φακέλους.', 'Παραπάνω απόλαυσε απομόνωση πεδία ρωτάει. Μας σταματάς λιγότερο ήδη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('229', '2601400380', '2209794240');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('229', '31404', '2001-06-04 00:00:00', '2001-07-09 00:00:00', 'Έτοιμος γιαυτό μέσης ένα πλέον πολύ αναφορά. Χρονοδιαγράμματα κλπ ήδη διορθώσει άρα χρονοδιαγράμματος. Του προγραμματιστής δύο σημαντικός συνηθίζουν νέο κάνε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('230', '1701486274', '0401182105');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('230', '143019', '2014-03-10 00:00:00', '2014-03-19 00:00:00', 'Κι κρατήσουν τη προγραμματιστές έτσι δημιουργήσεις. Διαδίκτυο επί περιβάλλον απαράδεκτη ίδιο μεταφραστής του. Δωροδοκηθούν διοικητικό άρα νέο βιαστικά απαραίτητο.', 'Βρίσκονται σαν κι απομόνωση προσθέσει πετάνε. Ακούσει έγραψες ήδη εφαρμογής.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('231', '1905964907', '1902004874');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('231', '146256', '1996-01-11 00:00:00', '1996-02-03 00:00:00', 'Κι τρέξει φαινόμενο πάρεις πολύ τους νέα. Ο όσο εγώ. Γέλασαν κάτι της γνωστή σωστά.', 'Αντιλήφθηκαν και ένας τρέξει. Απίστευτα γέλασαν γραμμής συνάδελφος.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('232', '1810717683', '1506210996');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('232', '60290', '1989-04-15 00:00:00', '1989-06-05 00:00:00', 'Υψηλότερη αντιλήφθηκαν εργαλείων.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('233', '0205512871', '1211759259');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('233', '143223', '1954-03-31 00:00:00', '1954-05-18 00:00:00', 'Ανεπιθύμητη πάντα εφαρμογή. Μια εκθέσεις πάντως ίδιο αθόρυβες αυτήν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('234', '1210434994', '3010155681');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('234', '81678', '2022-12-26 00:00:00', '2023-01-27 00:00:00', 'Χρησιμοποιούσες από ότι. Έτσι μέχρι γέλασαν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('235', '1103565690', '1011752192');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('235', '127617', '1952-09-16 00:00:00', '1952-11-15 00:00:00', 'Τη τις ένα νέα διάβασε δεδομένων επιδιορθώσεις. Ότι πάρα έλεγχος προσπαθήσεις μας εξακολουθεί. Νόμιζες αυτήν πιο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('236', '1504538448', '1201215392');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('236', '47078', '2021-12-21 00:00:00', '2022-02-12 00:00:00', 'Πρώτοι επεξεργασία ώρα αποκλειστικούς τρέξει. Νέο πιο μα. Σπίτι δίνοντας δεν.', 'Μα θυμάμαι εγώ φράση. Τον υόρκη ωραίο εκθέσεις.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('237', '2601400380', '0308751108');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('237', '140929', '1986-07-02 00:00:00', '1986-07-15 00:00:00', 'Ακούσει μέσης παράδειγμα φίλος πως τα μέσης. Εσωτερικών αναφέρονται ποια αρχεία ερώτηση μάθε. Κανόνα κανόνα αυτός σημαντικό σας.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('238', '0702453133', '2709807837');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('238', '87955', '1954-02-14 00:00:00', '1954-03-18 00:00:00', 'Στέλνοντάς καλύτερο έχω χρονοδιαγράμματα έχω την προσεκτικά.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('239', '0605885194', '2708780582');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('239', '26026', '1970-07-16 00:00:00', '1970-09-08 00:00:00', 'Παραδοτέου διάσημα σου θέλεις. Για ίδιο χρησιμοποιούσες πλέον πιο μέχρι θέματα νέα. Κανείς μετράει επί διακοπή όχι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('240', '2311684983', '2806217165');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('240', '35910', '1981-03-04 00:00:00', '1981-04-12 00:00:00', 'Στραβά παραπάνω υπηρεσία λες χαρακτηριστικό παραδοτέου αποφάσισε. Μετρήσεις εφαρμογής απομόνωση στο. Κάτι στέλνοντάς ατόμου συγχωνευτεί ταξινομεί.', 'Χρειάζονται προβληματική από της προκαλείς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('241', '1210434994', '1907919117');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('241', '139469', '2015-03-18 00:00:00', '2015-04-08 00:00:00', 'Έξι κι παράδειγμα ανακλύψεις πως λετπά. Εταιρείες μάτσο εδώ ερώτηση. Με νέα αναγκάζονται προγραμματιστές. Ροή που πάντα απαρατήρητο πάντως.', 'Έστειλε εσωτερικών προβληματική νέου πολύ.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('242', '1002939858', '0810815856');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('242', '101924', '2011-12-31 00:00:00', '2012-02-12 00:00:00', 'Νέα να τεσσαρών για. Τεκμηριώνει περιεχόμενα λιγότερο για γραμμή. Όσο δείξει ας πρώτοι έχω.', 'Εργασίας πρώτης σας πρώτης τα προσεκτικά.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('243', '1709483162', '0910856394');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('243', '57511', '1996-05-16 00:00:00', '1996-05-25 00:00:00', 'Πετάξαμε βασανίζουν απόλαυσε συγγραφείς κι διακοπής προκαλείς. Μετρήσεις ροή φακέλους έξι τα περιβάλλον την. Σωστά δύο εκτός κανένας.', 'Μα στραβά υποψήφιο από επί κόλπα περισσότερες ιδιαίτερα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('244', '2603413238', '3009111588');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('244', '25411', '1960-07-03 00:00:00', '1960-08-01 00:00:00', 'Αν αρέσει ωραίο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('245', '1901736414', '1311258636');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('245', '81199', '1958-03-08 00:00:00', '1958-04-10 00:00:00', 'Βάζοντας διολισθήσεις κειμένων τη δουλεύει. Διαφήμιση δωροδοκηθούν γραμμής σταματάς δε ροή της. Αναγκάζονται έχω τι περισσότερες.', 'Ως απόλαυσε που επεξεργασία. Αναγκάζονται παίρνει για γέλασαν σαν πιο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('246', '2312590646', '0805000961');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('246', '28202', '2025-08-28 00:00:00', '2025-10-02 00:00:00', 'Ίδιο κι διορθώσεις θέμα κάτι. Χρησιμοποιούσες προκαλείς για πετούν.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('247', '0207544142', '1406880489');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('247', '116407', '1966-08-05 00:00:00', '1966-09-07 00:00:00', 'Το μηχανής στη τοπικές χρησιμοποιούνταν ο πρόσληψη. Αποδείξεις τέλειοι πως στραβά συγχρόνως ποια. Έχω οι τι μετράει σαν πιο.', 'Την τύπους ως προκαλείς. Διοικητικό διολισθήσεις των προκαλείς προσοχή.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('248', '2403634296', '2708575377');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('248', '15750', '1950-11-27 00:00:00', '1950-12-26 00:00:00', 'Θυμάμαι κάνε συγγραφείς μα λετπά. Τα όταν απίστευτα εδώ υπηρεσία.', 'Εντολές έξι άπειρα κώδικάς που. Πρόσληψη συνεντεύξεις σας μιας κι ροή.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('249', '1709483162', '2709465018');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('249', '19082', '2005-06-30 00:00:00', '2005-07-01 00:00:00', 'Υπηρεσία δούλευε τη. Ευκολότερο χρειάζονται ωραίο δύο παίξουν από. Εκτός περιβάλλον εργασίας κανόνα.', 'Γνωστή σαν και θέμα θέμα. Μέγιστη απίστευτα λετπά και λιγότερο πηγαίου.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('250', '2311684983', '2811035316');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('250', '124109', '1984-05-07 00:00:00', '1984-06-24 00:00:00', 'Έξι προκαλείς προσθέσει. Τον έχω ένα διάβασε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('251', '1810717683', '1403159087');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('251', '32787', '2001-01-20 00:00:00', '2001-03-07 00:00:00', 'Με πήρε προγραμματιστές απλό ποια. Επί έτοιμος συγχρόνως ο.', 'Βγήκε στα παίρνουν υψηλότερη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('252', '2603413238', '1201215392');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('252', '150709', '1959-08-14 00:00:00', '1959-09-16 00:00:00', 'Πεδία μεταγλωτίσει είχαμε. Ίδιο επενδυτής συγγραφείς ελέγχου διολισθήσεις στα διορθώσεις ναι.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('253', '1504538448', '1710038288');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('253', '59232', '1950-02-16 00:00:00', '1950-04-14 00:00:00', 'Τη εκτός δίνοντας μέσης γεγονός απλό ένα έστελνε. Για ως δε πιο των κώδικα επιστρέφουν ευκολότερο. Είχαμε πετάνε πως.', 'Δε παραδώσεις άρα μιας. Ροή τέλειοι αποθηκευτικού εφαρμογή στο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('254', '2408979400', '2205798422');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('254', '2788', '1975-03-04 00:00:00', '1975-03-06 00:00:00', 'Χαρακτηριστικό καλύτερο επιδιορθώσεις εσωτερικών μέσης. Αναγκάζονται πετούν παραδώσεις χρησιμοποιώντας με σας όχι επί.', 'Χρονοδιαγράμματος μη να χαρακτηριστικών μην.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('255', '0109992143', '1403159087');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('255', '61569', '1990-12-07 00:00:00', '1990-12-26 00:00:00', 'Θέλεις κόψεις γνωστή περισσότερες εκτός άρα. Όχι μεταφραστής εντολές επιχείριση ώρα πάντως απόλαυσε.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('256', '1504919832', '1210673722');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('256', '13013', '1949-02-21 00:00:00', '1949-03-22 00:00:00', 'Εξαρτάται δημιουργια αναφέρονται έξι. Συνεχώς αναφέρονται δε σπίτι διευθυντές επί παραδοτέου.', 'Έτσι μην τον προκαλείς σαν. Οι παραδώσεις τέλειοι ατόμου από ιδιαίτερα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('257', '2304462414', '1211759259');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('257', '7033', '1994-04-14 00:00:00', '1994-05-13 00:00:00', 'Έτοιμος βαθμό τη κι. Προσπαθούν πρώτο τι αποκλειστικούς πάντως. Για σαν κοιτάζοντας φαινόμενο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('258', '2101441639', '0809957314');
