INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('259', '0702453133', '2312666072');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('259', '20021', '1997-08-14 00:00:00', '1997-09-05 00:00:00', 'Έτσι προσπαθήσεις εργασίας φαινόμενο βάζοντας. Πάντως έλεγχος σημαντικός με διακόψουμε πεδία. Εκδόσεις εσωτερικών κοιτάζοντας ένα πάντως ήδη. Σκεφτείς ιδιαίτερα εργαζόμενοι δουλεύει.', 'Δωροδοκηθούν εργαζόμενων τύπους πήρε ότι ροή προκύπτουν.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('260', '0702453133', '0308427033');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('260', '42215', '1965-01-09 00:00:00', '1965-01-27 00:00:00', 'Επιστρέφουν πετάνε νόμιζες από μετρήσεις κάνεις. Περίπου το εγώ σταματάς που. Λιγότερο όταν σε ημέρα φράση σημεία.', 'Μια κειμένων πρώτης προσπαθούν πρώτης λέει κάτι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('261', '1310995579', '2807919909');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('261', '144391', '1971-01-01 00:00:00', '1971-02-20 00:00:00', 'Θυμάμαι κόλπα έγραψες ένα. Δουλεύει που έχω μου διακοπής. Εκτελέσει δύο αποφάσισε μέσης συνηθίζουν.', 'Διαχειριστής στραβά πηγαίου μέγιστη δύο ένα δύο άρα. Μην το το άλγεβρα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('262', '1002939858', '0306752471');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('262', '100968', '1995-09-25 00:00:00', '1995-10-08 00:00:00', 'Λιγότερο πηγαίου εκτός που του μετράει. Πάντα εικόνες διασφαλίζεται δυστυχώς μάθε πάντως πετάξαμε.', 'Λες διακοπής εργαζόμενοι ίδιο βιβλίο.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('263', '0207540102', '1406488650');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('263', '112915', '2014-09-09 00:00:00', '2014-09-23 00:00:00', 'Πολύ δημιουργείς παράδειγμα πάντως στέλνοντάς ένα. Λετπά δουλεύει έξι διορθώσει μου παίρνουν.', 'Ανταγωνιστής διορθώσεις σημεία εργασίας μας έστειλε συγκεντρωμένοι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('264', '1504919832', '0104835316');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('264', '37329', '1973-06-21 00:00:00', '1973-06-28 00:00:00', 'Ημέρα πάρεις ρωτήσει πιο. Μην πετούν νόμιζες στη σου στις διολισθήσεις. Προγραμματιστές διαφήμιση σαν θα.', 'Έλεγχος στη αφήσεις. Απόλαυσε εργαλείων επί ανά μα πλέον απαράδεκτη και.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('265', '0207544142', '2009571737');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('265', '68187', '1983-11-04 00:00:00', '1983-12-02 00:00:00', 'Γεγονός θέματα του σου.', 'Περιμένουν ταξινομεί μη χαρακτηριστικό έτσι ύψος. Παραπάνω από τα γειτονιάς.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('266', '3005652478', '1609900460');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('266', '87155', '1976-11-04 00:00:00', '1976-12-14 00:00:00', 'Μέρος αποστηθίσει λιγότερο μέγιστη περισσότερη υποψήφιο.', 'Νέο για γιαυτό. Στα περισσότερη κι πιο τη γνωρίζουμε δε.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('267', '1701486274', '2209794240');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('267', '93530', '2016-12-10 00:00:00', '2017-02-07 00:00:00', 'Μετράει δύο άρθρων είχαμε απαραίτητο ναι συνεχώς. Εγώ διάβασε κάνε αγοράζοντας συγχωνευτεί μη. Ταξινομεί των όταν δημιουργια έξι στραβά κανένας έχω.', 'Πολύ δοκιμάσεις ζητήσεις κάτι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('268', '1909902990', '1109860119');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('268', '156340', '1961-12-27 00:00:00', '1962-02-13 00:00:00', 'Βγήκε έλεγχος να δε ως συνηθίζουν συνεχώς. Παραδοτέου διευθυντές δωροδοκηθούν πόρτες ποσοστό.
