INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('269', '79176', '2021-03-07 00:00:00', '2021-04-30 00:00:00', 'Ατόμου άπειρα μέγιστη έξι διοικητικό τη. Πλέον έτσι σε χρειάζονται των.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('270', '2609467791', '0703907278');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('270', '59663', '1952-03-24 00:00:00', '1952-05-15 00:00:00', 'Ατόμου ρουτίνα πολύ όχι κοιτάζοντας ποια δούλευε. Συγκεντρωμένοι πεδία εργαζόμενοι πετάνε πρόσληψη γραμμή εξακολουθεί.', 'Πολύ τις επί ύψος γεγονός. Αρέσει βγήκε κόψεις ήδη.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('271', '2207829834', '2807919909');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('271', '69329', '1947-09-21 00:00:00', '1947-11-09 00:00:00', 'Διάσημα χρησιμοποιούσες εδώ ιδιαίτερα στήλες αρέσει. Χρησιμοποιούσες μου παίξουν πακέτων. Έρθει έξι συγγραφής μας εκείνου επιχείριση.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('272', '2403634296', '0905574543');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('272', '143464', '2015-11-29 00:00:00', '2015-12-30 00:00:00', 'Κρατήσουν βρίσκονται πιο παραδώσεις πρώτο κύκλο. Πεδία δουλεύει έτσι τρόποι. Ώρα συγγραφής πιο με όχι στη. Τον πάντα μεταγλωτίσει.', 'Διευθυντές λετπά προσλάμβανες αποδείξεις πρώτο υποψήφιο τα.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('273', '1004904318', '0610232616');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('273', '102673', '2026-07-15 00:00:00', '2026-09-11 00:00:00', 'Χειρότερα απαρατήρητο επιστρέφουν νέων ροή μεταφραστής άρα. Και εικόνες γέλασαν αναφέρονται διοικητικό έχω πλέον πεδία.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('274', '1509007909', '1211759259');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('274', '76063', '1950-10-20 00:00:00', '1950-11-04 00:00:00', 'Πιο πρόσληψη άπειρα εργασίας. Εργάστηκε αρέσει ευκολότερο.', 'Μεταγλωτίσει μια λαμβάνουν μου παίρνουν νέα εφαρμογή.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('275', '0603460438', '1510001508');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('275', '62994', '2013-05-07 00:00:00', '2013-06-18 00:00:00', 'Αποφάσισε ίδιο χρησιμοποίησέ ποια να κύκλο. Δυστυχώς ανώδυνη θέλεις νέο τον περιεχόμενα. Απλό προϊόντα μέχρι ποια απίστευτα. Κι για άπειρα.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('276', '1910624895', '1404027826');
