INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('277', '1510499016', '0104835316');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('277', '4241', '1976-10-04 00:00:00', '1976-11-21 00:00:00', 'Ανώδυνη δημιουργια προσοχή τέλειοι πολύ μεταγλωτίσει αποδείξεις. Βιβλίο προσοχή και διορθώσει. Πλέον πες υψηλότερη δεν προγραμματιστές σε. Κώδικάς αντιλήφθηκαν σου γράψει απαρατήρητο πλέον.', 'Δύο χρησιμοποιώντας γνωστή οι λετπά έτσι.');
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('278', '2011999624', '2009571737');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('278', '121615', '1968-03-30 00:00:00', '1968-05-07 00:00:00', 'Επενδυτής εκτός φίλος δεν τοπικές σαν γιαυτό. Κειμένων σταματάς πλέον πάντως την. Έστελνε συνέχεια έτσι τους δύο.
