INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('279', '55396', '1980-07-06 00:00:00', '1980-07-27 00:00:00', 'Μέσης αρχεία στήλες έλεγχος νιρβάνα. Πάρα εκδόσεις εγώ δε ίδιο στο.
INSERT INTO prescription (prescription_id, doctor_id, patient_id) VALUES ('280', '2207829834', '2005204831');
